def getInvalidInstrCacheStats():
	pct = (float(_invalid_instr_cache_hits) / float(_invalid_instr_cache_requests) * 100.0) if _invalid_instr_cache_requests else 0.0
	return _invalid_instr_cache_hits, _invalid_instr_cache_requests, _invalid_instr_cache_stores, pct


def _mask_config_debug_line(line_text):
	try:
		line = ensure_text(line_text).rstrip("\r\n")
	except Exception:
		line = str(line_text).rstrip("\r\n")
	line_stripped = line.strip()
	if "=" not in line_stripped:
		return line
	param, value = line_stripped.split("=", 1)
	param = param.strip().lower()
	if param.endswith(".key") or "api_key" in param or "apikey" in param:
		return "%s=<masked>" % param
	return line


def _isUnreadablePageCached(page_start):
	global _unreadable_page_cache
	global _unreadable_page_cache_requests
	global _unreadable_page_cache_hits
	try:
		page_start = int(page_start)
	except Exception:
		return False
	_unreadable_page_cache_requests += 1
	if page_start in _unreadable_page_cache:
		_unreadable_page_cache_hits += 1
		return True
	return False


def _markUnreadablePageCached(page_start):
	global _unreadable_page_cache
	try:
		_unreadable_page_cache[int(page_start)] = True
	except Exception:
		pass



