class MnDebugger:

	def __init__(self):
		self.dbg = dbglib.Debugger()

	def _integerTypes(self):
		try:
			return (int, long)
		except NameError:
			return (int,)

	def isWinDBG(self):
		if __DEBUGGERAPP__ == "WinDBG":
			return True
		return False		

	def isImmunity(self):
		if __DEBUGGERAPP__ == "Immunity Debugger":
			return True
		return False

	def execOSCommand(self, command_array, nowait=False):
		"""Execute an OS command from an argument array and optionally capture its output."""
		if not isinstance(command_array, (list, tuple)) or len(command_array) == 0:
			raise ValueError("execOSCommand requires a non-empty array with the command and arguments")
		command_args = [ensure_text(arg) for arg in command_array]
		popen_kwargs = {}
		if os.name == "nt":
			try:
				startupinfo = subprocess.STARTUPINFO()
				startupinfo.dwFlags |= subprocess.STARTF_USESHOWWINDOW
				popen_kwargs["startupinfo"] = startupinfo
			except Exception:
				pass
			if hasattr(subprocess, "CREATE_NO_WINDOW"):
				popen_kwargs["creationflags"] = subprocess.CREATE_NO_WINDOW
		if nowait:
			devnull_handle = None
			try:
				devnull_handle = open(os.devnull, "wb")
				subprocess.Popen(
					command_args,
					stdout=devnull_handle,
					stderr=devnull_handle,
					stdin=devnull_handle,
					**popen_kwargs
				)
			finally:
				if devnull_handle is not None:
					devnull_handle.close()
			return []
		devnull_handle = None
		try:
			# WinDBG-hosted Python may expose invalid inherited stdin handles.
			# Provide an explicit benign stdin so child process creation remains stable.
			devnull_handle = open(os.devnull, "rb")
			process = subprocess.Popen(
				command_args,
				stdout=subprocess.PIPE,
				stderr=subprocess.STDOUT,
				stdin=devnull_handle,
				**popen_kwargs
			)
			output_data = process.communicate()[0]
		finally:
			if devnull_handle is not None:
				devnull_handle.close()
		output_text = ensure_text(output_data)
		return output_text.split("\n")

	def validateCpbArgument(self, args, log_error=None, log_error_detail=None, debug_label=""):
		"""Validate -cpb syntax early so callers do not continue with a silently ignored badchar filter."""
		mndbg.dbgp(get_current_function_name())
		if "cpb" not in args:
			return True
		if type(args["cpb"]).__name__.lower() == "bool":
			if callable(log_error):
				log_error("Please specify badchars with -cpb <bytes>")
			if callable(log_error_detail):
				log_error_detail("Example: -cpb '\\x00\\x0a\\x0d'")
			return False
		strb, badcharsok = cpbArgToBytes(args["cpb"])
		if not badcharsok:
			if callable(log_error):
				log_error("Unable to parse -cpb value '%s'" % args["cpb"])
			if callable(log_error_detail):
				log_error_detail("Use \\xNN byte syntax, for example: -cpb '\\x00\\x20\\x0a\\x0d\\x3f'")
				log_error_detail("Ranges are also supported, for example: -cpb '\\x00..\\x05\\x20\\x3f'")
			return False
		debug_prefix = ensure_text(debug_label).strip() or "cpb"
		mndbg.dbgp("%s: validated -cpb value '%s' -> %s" % (
			debug_prefix,
			args["cpb"],
			_renderBadchars(strb)
		))
		return True

	def launchDetachedCommand(self, command_array, output_path="", redirect_output=True):
		"""Launch a detached OS command and optionally redirect stdout/stderr to a log file."""
		if not isinstance(command_array, (list, tuple)) or len(command_array) == 0:
			raise ValueError("launchDetachedCommand requires a non-empty array with the command and arguments")
		command_args = [ensure_text(arg) for arg in command_array]
		stdout_target = None
		stderr_target = None
		stdin_target = None
		log_handle = None
		popen_kwargs = {}
		if os.name == "nt":
			try:
				startupinfo = subprocess.STARTUPINFO()
				startupinfo.dwFlags |= subprocess.STARTF_USESHOWWINDOW
				popen_kwargs["startupinfo"] = startupinfo
			except Exception:
				pass
			if hasattr(subprocess, "CREATE_NO_WINDOW"):
				popen_kwargs["creationflags"] = subprocess.CREATE_NO_WINDOW
		if redirect_output:
			if output_path != "":
				output_dir = os.path.dirname(output_path)
				if output_dir != "" and not os.path.isdir(output_dir):
					try:
						os.makedirs(output_dir)
					except OSError:
						if not os.path.isdir(output_dir):
							raise
				log_handle = open(output_path, "wb")
				stdout_target = log_handle
				stderr_target = log_handle
			else:
				devnull_handle = open(os.devnull, "wb")
				log_handle = devnull_handle
				stdout_target = devnull_handle
				stderr_target = devnull_handle
				stdin_target = devnull_handle
		try:
			process = subprocess.Popen(
				command_args,
				stdout=stdout_target,
				stderr=stderr_target,
				stdin=stdin_target,
				close_fds=False,
				**popen_kwargs
			)
		finally:
			if log_handle is not None:
				log_handle.close()
		return process.pid

	def getWinDBGVersion(self):
		"""
		Determine whether the current debugger host appears to be WinDBGX.

		Detection logic:
			WinDBG Classic is normally launched as windbg.exe from the Windows Kits
			Debuggers folder.

			WinDBGX does not run the debugger engine directly as windbg.exe.
			The engine host runs via EngHost.exe from the WindowsApps package path,
			for example:

				C:\\Program Files\\WindowsApps\\Microsoft.WinDbg_...\\x86\\EngHost.exe

			Therefore, we detect WinDBGX by looking for strong indicators in the
			'version' output:
				- WindowsApps\\Microsoft.WinDbg_
				- EngHost.exe
				- npipe:pipe=DbgX_

			These are much better indicators than the dbgeng version number,
			because both Classic and WinDBGX report a Microsoft Windows Debugger
			engine version in the 10.x range.
		"""

		if self.isWinDBG():

			global g_windbg_flavor
			global g_windbg_pretty_name

			if g_windbg_flavor == "" or g_windbg_flavor == "unknown":

				version_lines = []

				try:
					output = self.dbg.nativeCommand("version")
					version_lines = output.split("\n")
				except:
					self.dbgp("Unable to execute command to get WinDBG version")

				if not version_lines:
					# assume it's windbg classic
					g_windbg_flavor = "windbg"
					g_windbg_pretty_name = "WinDBG Classic"
					return


				text = "\n".join([str(line) for line in version_lines])
				text_l = text.lower()

				windbgx_indicators = [
					"windowsapps\\microsoft.windbg_",
					"enghost.exe",
					"npipe:pipe=dbgx_"
				]

				classic_indicators = [
					"windbg.exe",
					"\\windows kits\\10\\debuggers\\",
					"\\windows kits\\8.1\\debuggers\\",
					"\\windows kits\\8.0\\debuggers\\"
				]

				matched_windbgx = []
				for indicator in windbgx_indicators:
					if indicator in text_l:
						matched_windbgx.append(indicator)

				if matched_windbgx:
					g_windbg_flavor = "windbgx"
					g_windbg_pretty_name = "WinDBGX"
					return

				matched_classic = []
				for indicator in classic_indicators:
					if indicator in text_l:
						matched_classic.append(indicator)

				if matched_classic:
					g_windbg_flavor = "windbg"
					g_windbg_pretty_name = "WinDBG Classic"
					return

				g_windbg_flavor = "unknown"
				g_windbg_pretty_name = "Unknown Debugger"

	def get_current_datetime(self):
		return time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(time.time()))

	def get_current_datetime_flat(self):
		return time.strftime("%Y%m%d-%H%M%S", time.localtime(time.time()))

	def dbgp(self, s, highlight=False, errormode = False):
		# print debug information
		global g_dbgp_counter
		msgprefix = ""
		if errormode:
			msgprefix = " - ERR"
			highlight = True
		if DEBUG_MODE:
			g_dbgp_counter += 1
			try:
				self.dbg.log("[MONA DEBUG%s] %s | %s" % (msgprefix, self.get_current_datetime(),s), highlight=highlight)
			except Exception as e:
				self.dbg.log("[MONA DEBUG - error] %s | %s" % (self.get_current_datetime(), str(e)), highlight=True)
				pass
				if (g_dbgp_counter % 500) == 0:
					interruptMona()

	def _parseAddressToken(self, token):
		self.dbgp(get_current_function_name())
		try:
			cleaned = ensure_text(token).strip().replace("`", "")
		except Exception:
			cleaned = str(token).strip().replace("`", "")
		if cleaned == "":
			return 0
		cleaned = cleaned.rstrip(":,;")
		cleaned = cleaned.replace("0x", "", 1)
		if isAddress(cleaned):
			return hexStrToInt(cleaned)
		return 0

	def _extractDisassemblyLabel(self, disasm_text):
		self.dbgp(get_current_function_name())
		if not disasm_text:
			return ""
		for raw_line in ensure_text(disasm_text).splitlines():
			line = raw_line.strip()
			if line == "":
				continue
			if line.endswith(":"):
				return line[:-1].strip()
			break
		return ""

	def isAddressInOutput(self, output, address):
		self.dbgp(get_current_function_name())
		if not isinstance(address, self._integerTypes()) or address <= 0:
			return False
		if not output:
			return False
		entries = _parseDisassemblyTextEntries(output)
		if len(entries) == 0:
			return False
		for entry in entries:
			if entry.get("address", 0) == address:
				return True
		return False

	def _functionViaUf(self, address):
		self.dbgp(get_current_function_name())
		result = {
			"address": address,
			"start": 0,
			"symbol": "",
			"method": "uf",
			"offset": "",
			"found": False,
			"disasm": "",
		}
		if not isinstance(address, self._integerTypes()) or address <= 0:
			return result
		if not self.isWinDBG():
			return result
		try:
			output = ensure_text(self.dbg.nativeCommand("uf %s" % (PTR_PRINT % address))).strip()
		except Exception:
			return result
		result["disasm"] = output
		if not self.isAddressInOutput(output, address):
			return result

		entries = _parseDisassemblyTextEntries(output)
		function_start = entries[0].get("address", 0)
		if not isinstance(function_start, self._integerTypes()) or function_start <= 0:
			return result

		result["found"] = True
		result["start"] = function_start
		if address >= function_start:
			result["offset"] = "0x%x" % (address - function_start)

		try:
			fname, foffset = getFunctionName(function_start)
			if fname != "" and (foffset == "" or str(foffset) == "0"):
				result["symbol"] = fname
		except Exception:
			pass
		if result["symbol"] == "":
			try:
				funcinfo = dbglib.Function(dbg, function_start)
				symname = ensure_text(funcinfo.addressToSymbol()).strip()
				if symname != "":
					result["symbol"] = symname
			except Exception:
				pass
		if result["symbol"] == "":
			result["symbol"] = self._extractDisassemblyLabel(output)

		return result

	def _ensureSymbolCache(self, auto_fix=False):
		"""Check that WinDBG has a valid local symbol cache configured.

		Returns a list of valid local filesystem cache directories.
		If none are found and auto_fix is True, sets a default symbol path.
		If none are found and auto_fix is False, logs a warning and returns [].
		Also populates _symbol_dirs_cache for use by showModuleTable.
		"""
		global _symbol_dirs_cache
		if not self.isWinDBG():
			return []

		# this will initialize g_windbg_flavor to either "windbg" or "windbgx"
		# and g_windbg_pretty_name to "WinDBG Classic" or "WinDBGX"
		self.getWinDBGVersion()

		self.dbgp("Active Debugger Flavor: %s" % g_windbg_pretty_name)

		raw = dbglib.getSymbolPath().replace(" ", "")
		ms_symbol_server = "https://msdl.microsoft.com/download/symbols"
		if raw == "":
			if auto_fix:
				self.dbg.log("")
				self.dbg.log("** Warning, no symbol path set ! ** ", highlight=1)
				sympath = "srv*c:\\symbols*%s" % ms_symbol_server
				self.dbg.log("   I'll set the symbol path to %s" % sympath)
				dbglib.setSymbolPath(sympath)
				self.dbg.log("   Symbol path set, now reloading symbols...")
				self.dbg.nativeCommand(".reload")
				self.dbg.log("   All set. Please restart WinDBG.")
				self.dbg.log("")
			else:
				self.dbg.log("[!] No symbol path configured", highlight=1)
				self.dbg.log("    Configure a symbol path first, e.g.:")
				self.dbg.log("    .sympath srv*c:\\symbols*%s" % ms_symbol_server)
				return []

		cache_dirs, servers, sym_entries = dbglib.getSymPaths(g_windbg_flavor)
		cache_dirs = [d for d in cache_dirs if d and not d.lower().startswith(("http://", "https://"))]

		self.dbgp("Cache_dirs: %s" % cache_dirs)
		for d in cache_dirs:
			self.dbgp("%s" % d)

		if cache_dirs:
			_symbol_dirs_cache = cache_dirs

		if not cache_dirs and not auto_fix:
			self.dbg.log("[!] No valid local symbol cache directory found in .sympath", highlight=1)
			self.dbg.log("    Configure a symbol path with a local cache, e.g.:")
			self.dbg.log("    .sympath srv*c:\\symbols*%s" % ms_symbol_server)

		return cache_dirs


mndbg = MnDebugger()
dbg = mndbg.dbg

def _findSymbolsCached(mod, cache_dirs=None):
	"""Find a module's cached PDB path.

	Checks next to the binary first, then symbol cache directories.

	Returns: (path_str, label) or (None, None) if not found.
	  label is "local" or "#N" (1-based cache dir index).
	"""
	pdbname = mod.modulePdbName
	guidage = mod.modulePdbGuidAge
	modpath = mod.modulePath
	if modpath and pdbname:
		local_pdb = os.path.join(os.path.dirname(modpath), pdbname)
		if os.path.isfile(local_pdb):
			return local_pdb, "local"
	dirs = cache_dirs if cache_dirs is not None else _symbol_dirs_cache
	if dirs is not None and pdbname and guidage:
		for ci, cdir in enumerate(dirs):
			candidate = os.path.join(cdir, pdbname, guidage, pdbname)
			if os.path.isfile(candidate):
				return candidate, "#%d" % (ci + 1)
	return None, None


def _hasSymbolsCached(mod):
	"""Check if a module's PDB is cached. Returns True/False/None."""
	pdbname = mod.modulePdbName
	modpath = mod.modulePath
	# Local check doesn't need _symbol_dirs_cache
	if modpath and pdbname:
		local_pdb = os.path.join(os.path.dirname(modpath), pdbname)
		if os.path.isfile(local_pdb):
			return True
	if _symbol_dirs_cache is None:
		return None
	path, _ = _findSymbolsCached(mod)
	return path is not None

