def _renderRegistersText():
	mndbg.dbgp(get_current_function_name())
	lines = []
	try:
		regs = getAllRegisters()
		for reg_name in sorted(regs.keys()):
			reg_val = regs[reg_name]
			if isinstance(reg_val, int):
				lines.append("%s = %s" % (reg_name.lower(), PTR_PRINT % reg_val))
			else:
				lines.append("%s = %s" % (reg_name.lower(), _formatContextText(reg_val)))
	except Exception as e:
		lines.append("Unable to read registers: %s" % str(e))
	return "\n".join(lines)


def _renderStackText(max_bytes=0x1000):
	mndbg.dbgp(get_current_function_name())
	lines = []
	try:
		if mnproc is None:
			return "Unable to resolve current process context"
		teb = mnproc.getCurrentTEB()
		regs = getAllRegisters()
		sp = regs.get(STACK_POINTER, 0)
		if teb is None or not isinstance(sp, int) or sp <= 0:
			return "Unable to resolve current stack context"
		start = max(teb.StackLimit, sp)
		end = min(teb.StackBase, start + max_bytes)
		lines.append("Current stack range: %s - %s (SP=%s)" % (PTR_PRINT % start, PTR_PRINT % end, PTR_PRINT % sp))
		if end <= start:
			lines.append("No readable stack range selected")
			return "\n".join(lines)
		cursor = start
		while cursor < end:
			read_len = min(16, end - cursor)
			try:
				raw = dbg.readMemory(cursor, read_len)
				ascii_data = "".join([chr(b) if 32 <= b <= 126 else "." for b in bytearray(raw)])
				hex_data = " ".join(["%02x" % b for b in bytearray(raw)])
				lines.append("%s : %-47s | %s" % (PTR_PRINT % cursor, hex_data, ascii_data))
			except Exception as e:
				lines.append("%s : <unreadable> (%s)" % (PTR_PRINT % cursor, str(e)))
			cursor += read_len
		if end < teb.StackBase:
			lines.append("... truncated at 0x%x bytes from current stack pointer" % max_bytes)
	except Exception as e:
		lines.append("Unable to render stack contents: %s" % str(e))
	return "\n".join(lines)


def _renderLayoutCategoriesText(categories, include_chunks=True):
	mndbg.dbgp(get_current_function_name())
	lines = []
	try:
		if mnproc is None:
			return "Unable to resolve current process context"
		for start, end, category, description in mnproc.getAllSorted(include_chunks=include_chunks):
			if category in categories:
				lines.append("%s - %s | %s | %s" % (
					PTR_PRINT % start,
					PTR_PRINT % end,
					category,
					stripTags(description)
				))
	except Exception as e:
		lines.append("Unable to collect layout categories %s: %s" % (",".join(sorted(categories)), str(e)))
	return "\n".join(lines)


def _renderModulesText(focus_addresses=None, max_modules=25):
	mndbg.dbgp(get_current_function_name())
	lines = []
	try:
		if mnproc is None:
			return "Unable to resolve current process context"
		items = sorted(mnproc.getPEB().getModules().items(), key=lambda x: x[1].moduleBase)
		for _, mod in items:
			lines.append(
				"%s | base=%s | top=%s | rebase=%s | aslr=%s | safeseh=%s | cfg=%s" % (
					mod.moduleFilename or mod.moduleKey,
					PTR_PRINT % mod.moduleBase,
					PTR_PRINT % mod.moduleTop,
					str(mod.isRebase),
					str(mod.isAslr),
					str(mod.isSafeSEH),
					str(mod.isCFG)
				)
			)
	except Exception as e:
		lines.append("Unable to collect module information: %s" % str(e))
	return "\n".join(lines)


def _getNtGlobalFlagSummary():
	mndbg.dbgp(get_current_function_name())
	info = OrderedDict()
	try:
		if mnproc is None:
			return {"error": "Unable to resolve current process context"}
		peb = mnproc.getPEB()
		current_flag = peb.getNtGlobalFlag()
		flag_values = peb.getNtGlobalFlagValues(current_flag)
		info["value"] = "0x%08x" % current_flag
		info["flags"] = []
		for flag_value in flag_values:
			short_name, description = peb.getNtGlobalFlagValueData(flag_value)
			info["flags"].append(OrderedDict([
				("value", "0x%08x" % flag_value),
				("short_name", short_name),
				("description", description),
				("display", peb.getNtGlobalFlagValueName(flag_value))
			]))
		if len(info["flags"]) == 0:
			info["summary"] = "No GFlags set"
		else:
			info["summary"] = ", ".join([entry["display"] for entry in info["flags"]])
	except Exception as e:
		info["error"] = str(e)
	return info


def _getSehChainSummary():
	mndbg.dbgp(get_current_function_name())
	info = OrderedDict()
	if arch != 32:
		info["error"] = "Structured Exception Handling chain collection is only applicable on 32-bit targets"
		return info
	try:
		sehchain = dbg.getSehChain()
		info["count"] = len(sehchain)
		if len(sehchain) > 0:
			info["start"] = PTR_PRINT % sehchain[0][0]
		info["records"] = []
		info["overwritten"] = []
		for sehrecord in sehchain:
			try:
				recaddress = sehrecord[0]
				sehandler = sehrecord[1]
				entry = OrderedDict()
				entry["record"] = PTR_PRINT % recaddress
				nsehvalue = 0
				try:
					nsehvalue = struct.unpack('<L', dbg.readMemory(recaddress, 4))[0]
				except Exception:
					pass
				entry["next_seh"] = "0x%08x" % nsehvalue
				entry["handler"] = PTR_PRINT % sehandler if isinstance(sehandler, int) and sehandler > 0 else "0x00000000"
				try:
					function_name = ""
					if isinstance(sehandler, int) and sehandler > 0:
						function_name = _getSymbolName(sehandler)
						if function_name == "":
							function_name = _getNearestSymbolOutput(sehandler)
					entry["function"] = _formatContextText(function_name, max_len=512)
				except Exception as e:
					entry["function_error"] = str(e)
					entry["function"] = ""
				info_text = ""
				try:
					overwritedata = checkSEHOverwrite(recaddress, nsehvalue, sehandler)
					if len(overwritedata) > 0:
						smashoffset = int(overwritedata[1])
						if overwritedata[0] == "unicode":
							smashoffset += 2
						info_text = "Smashed, offset %d%s" % (
							smashoffset,
							" [unicode]" if overwritedata[0] == "unicode" else ""
						)
						info["overwritten"].append(OrderedDict([
							("record", PTR_PRINT % recaddress),
							("type", _formatContextText(overwritedata[0], max_len=64)),
							("offset", int(overwritedata[1]))
						]))
				except Exception as e:
					entry["overwrite_check_error"] = str(e)
				if nsehvalue == 0xffffffff and info_text == "":
					info_text = "End of SEH chain"
				entry["info"] = _formatContextText(info_text, max_len=512)
				info["records"].append(entry)
			except Exception as e:
				info["records"].append(OrderedDict([
					("record_error", str(e))
				]))
		if len(info["overwritten"]) == 0:
			del info["overwritten"]
	except Exception as e:
		info["error"] = str(e)
	return info


def _getFindMspSummary(args=None):
	mndbg.dbgp(get_current_function_name())
	info = OrderedDict()
	osilent = None
	dbg.log("[+] Running findmsp")
	try:
		global g_silent
		osilent = g_silent
		g_silent = True
		mspresults = goFindMSP(100, args or {})
		info["distance"] = 100
		register_trampolines = {}
		raw_registers_to = mspresults.get("registers_to", {})
		if raw_registers_to:
			modulecriteria = {
				"aslr": False,
				"rebase": False,
			}
			trampoline_criteria = {
				"accesslevel": "X",
			}
			if args and "cpb" in args and type(args["cpb"]).__name__.lower() != "bool":
				strb, badcharsok = cpbArgToBytes(args["cpb"])
				if badcharsok and strb not in [None, b"", ""]:
					trampoline_criteria["badchars"] = strb
			global g_ptr_to_get
			global g_ptr_counter
			old_ptr_to_get = g_ptr_to_get
			old_ptr_counter = g_ptr_counter
			try:
				for reg_name in sorted(raw_registers_to.keys()):
					g_ptr_to_get = 1
					g_ptr_counter = 0
					jmp_results = findJMP(modulecriteria, trampoline_criteria, reg_name.lower())
					for instruction in jmp_results:
						pointers = jmp_results[instruction]
						if len(pointers) > 0:
							register_trampolines[reg_name] = OrderedDict([
								("address", PTR_PRINT % pointers[0]),
								("instruction", _formatContextText(instruction, max_len=256))
							])
							break
			finally:
				g_ptr_to_get = old_ptr_to_get
				g_ptr_counter = old_ptr_counter
		for key in ["registers", "registers_to", "seh", "memory", "stack", "stackcontains"]:
			raw = mspresults.get(key, {})
			if not raw:
				continue
			if key in ["registers", "registers_to"]:
				section = OrderedDict()
				for name in sorted(raw.keys()):
					value = raw[name]
					entry = OrderedDict()
					if len(value) > 0:
						entry["address"] = PTR_PRINT % value[0]
					if len(value) > 1:
						entry["offset"] = int(value[1])
					if len(value) > 2:
						if key == "registers":
							entry["pattern_type"] = _formatContextText(value[2], max_len=64)
						else:
							entry["length"] = int(value[2])
					if len(value) > 3:
						entry["pattern_type"] = _formatContextText(value[3], max_len=64)
					if key == "registers_to" and name in register_trampolines:
						entry["trampoline"] = register_trampolines[name]
					section[name] = entry
				info[key] = section
			elif key == "seh":
				section = []
				for sehaddr in sorted(raw.keys()):
					value = raw[sehaddr]
					entry = OrderedDict()
					entry["seh_handler"] = PTR_PRINT % sehaddr
					if len(value) > 0:
						entry["handler"] = PTR_PRINT % value[0]
					if len(value) > 1:
						entry["offset"] = int(value[1])
					if len(value) > 2:
						entry["pattern_type"] = _formatContextText(value[2], max_len=64)
					if len(value) > 3:
						entry["trailing_pattern_length"] = int(value[3])
					section.append(entry)
				info[key] = section
			elif key == "memory":
				section = []
				for address in sorted(raw.keys()):
					value = raw[address]
					entry = OrderedDict()
					entry["address"] = PTR_PRINT % address
					if len(value) > 0:
						entry["length"] = int(value[0])
					if len(value) > 1:
						entry["pattern_type"] = _formatContextText(value[1], max_len=64)
					section.append(entry)
				info[key] = section
			else:
				section = []
				for address in sorted(raw.keys()):
					value = raw[address]
					entry = OrderedDict()
					entry["address"] = PTR_PRINT % address
					if len(value) > 0:
						entry["stack_offset"] = int(value[0])
					if len(value) > 1:
						entry["stack_direction"] = _formatContextText(value[1], max_len=8)
					if len(value) > 2:
						entry["pattern_offset"] = int(value[2])
					if len(value) > 3:
						entry["length"] = int(value[3])
					if len(value) > 4:
						entry["pattern_type"] = _formatContextText(value[4], max_len=64)
					section.append(entry)
				info[key] = section
	except Exception as e:
		info["error"] = str(e)
		info["error_type"] = e.__class__.__name__
		info["error_traceback"] = safeTracebackText()
		mndbg.dbgp("tellme: _getFindMspSummary failed:\n%s" % info["error_traceback"], errormode=False)
	finally:
		if not osilent is None:
			g_silent = osilent
	return info


def _getFindSehSummaryFromFindmsp(findmsp_summary, args=None):
	mndbg.dbgp(get_current_function_name())
	info = OrderedDict()
	seh_entries = []
	if isinstance(findmsp_summary, dict):
		raw_seh = findmsp_summary.get("seh", [])
		if isinstance(raw_seh, list):
			seh_entries = raw_seh
	if len(seh_entries) == 0:
		return info

	modulecriteria = {
		"safeseh": False,
		"rebase": False,
		"aslr": False,
		"os": False,
	}
	sehcriteria = {}
	if args and args.get("n", False):
		sehcriteria["nonull"] = True
	if args and "cpb" in args and type(args["cpb"]).__name__.lower() != "bool":
		strb, badcharsok = cpbArgToBytes(args["cpb"])
		if badcharsok and strb not in [None, b"", ""]:
			sehcriteria["badchars"] = strb

	for entry in seh_entries:
		pattern_type = ensure_text(entry.get("pattern_type", "")).lower()
		if "unicode" in pattern_type:
			sehcriteria["unicode"] = True
			if "nonull" in sehcriteria:
				del sehcriteria["nonull"]
			break

	global g_silent
	global g_ptr_to_get
	global g_ptr_counter
	old_silent = g_silent
	old_ptr_to_get = g_ptr_to_get
	old_ptr_counter = g_ptr_counter
	try:
		g_silent = True
		g_ptr_counter = 0
		g_ptr_to_get = 1
		seh_pointers = findSEH(modulecriteria, sehcriteria)
	finally:
		g_silent = old_silent
		g_ptr_to_get = old_ptr_to_get
		g_ptr_counter = old_ptr_counter

	info["triggered"] = True
	info["seh_overwrites"] = seh_entries
	info["search"] = OrderedDict([
		("module_criteria", modulecriteria),
		("pointer_criteria", OrderedDict([
			("unicode", bool(sehcriteria.get("unicode", False))),
			("nonull", bool(sehcriteria.get("nonull", False))),
			("badchars", _renderBadchars(sehcriteria.get("badchars", b"")))
		]))
	])
	info["candidates"] = []
	for instruction in sorted(seh_pointers.keys()):
		pointers = seh_pointers[instruction]
		if len(pointers) == 0:
			continue
		info["candidates"].append(OrderedDict([
			("instruction", _formatContextText(instruction, max_len=256)),
			("address", PTR_PRINT % pointers[0])
		]))
	if len(info["candidates"]) == 0:
		info["no_candidates_found"] = True
	return info


def _getJsonSizeBytes(value):
	mndbg.dbgp(get_current_function_name())
	try:
		return len(json.dumps(value, ensure_ascii=False).encode("utf-8"))
	except Exception:
		try:
			return len(ensure_text(value).encode("utf-8"))
		except Exception:
			return len(str(value))


def _appendOmittedSection(omitted_sections, name, original_value, reason, retrieval_hint=""):
	mndbg.dbgp(get_current_function_name())
	entry = OrderedDict()
	entry["name"] = name
	entry["original_size_bytes"] = _getJsonSizeBytes(original_value)
	entry["reason"] = reason
	if retrieval_hint != "":
		entry["how_to_retrieve"] = retrieval_hint
	omitted_sections.append(entry)


def _extractWindbgAnalyzeSummary(output):
	mndbg.dbgp(get_current_function_name())
	info = OrderedDict()
	if output == "":
		return info
	lines = output.splitlines()
	for idx, raw_line in enumerate(lines):
		line = raw_line.strip()
		if line == "":
			continue
		upper_line = line.upper()
		if upper_line.startswith("EXCEPTION_CODE:"):
			info["exception_code"] = _formatContextText(line.split(":", 1)[1].strip(), max_len=256)
		elif upper_line.startswith("READ_ADDRESS:"):
			info["read_address"] = _formatContextText(line.split(":", 1)[1].strip(), max_len=256)
			info["access_type"] = "read"
		elif upper_line.startswith("WRITE_ADDRESS:"):
			info["write_address"] = _formatContextText(line.split(":", 1)[1].strip(), max_len=256)
			info["access_type"] = "write"
		elif upper_line.startswith("FAULTING_IP:"):
			faulting_ip = []
			for follow_line in lines[idx + 1:idx + 4]:
				follow_text = follow_line.strip()
				if follow_text == "":
					continue
				if ":" in follow_text and follow_text.upper() == follow_text:
					break
				faulting_ip.append(_formatContextText(follow_text, max_len=256))
			if len(faulting_ip) > 0:
				info["faulting_ip"] = faulting_ip
		elif upper_line.startswith("DEFAULT_BUCKET_ID:"):
			info["default_bucket_id"] = _formatContextText(line.split(":", 1)[1].strip(), max_len=256)
		elif upper_line.startswith("FAILURE_BUCKET_ID:"):
			info["failure_bucket_id"] = _formatContextText(line.split(":", 1)[1].strip(), max_len=256)
		elif upper_line.startswith("PRIMARY_PROBLEM_CLASS:"):
			info["primary_problem_class"] = _formatContextText(line.split(":", 1)[1].strip(), max_len=256)
		elif "APPLICATION_VERIFIER" in upper_line or "VERIFIER STOP" in upper_line or "VERIFIER" in upper_line:
			if "verifier_indicators" not in info:
				info["verifier_indicators"] = []
			if len(info["verifier_indicators"]) < 8:
				info["verifier_indicators"].append(_formatContextText(line, max_len=256))
		elif "PAGEHEAP" in upper_line or "PAGE HEAP" in upper_line:
			if "pageheap_indicators" not in info:
				info["pageheap_indicators"] = []
			if len(info["pageheap_indicators"]) < 8:
				info["pageheap_indicators"].append(_formatContextText(line, max_len=256))
	if "read_address" not in info and "write_address" not in info:
		for idx, raw_line in enumerate(lines):
			line = raw_line.strip()
			if line.upper().startswith("EXCEPTION_RECORD:") and idx + 1 < len(lines):
				next_line = lines[idx + 1].strip()
				if "read" in next_line.lower():
					info["access_type"] = "read"
				elif "write" in next_line.lower():
					info["access_type"] = "write"
	return info


def _simplifyWindbgAnalyze(analyze_info):
	mndbg.dbgp(get_current_function_name())
	if not isinstance(analyze_info, dict):
		return analyze_info
	simplified = OrderedDict()
	if "command" in analyze_info:
		simplified["command"] = analyze_info["command"]
	if "error" in analyze_info:
		simplified["error"] = analyze_info["error"]
		return simplified
	output = ensure_text(analyze_info.get("output", "")).strip()
	if output == "":
		return simplified
	for key, value in _extractWindbgAnalyzeSummary(output).items():
		simplified[key] = value
	return simplified


def _summarizeHeapCommandOutput(heap_info):
	mndbg.dbgp(get_current_function_name())
	summary = OrderedDict()
	if not isinstance(heap_info, dict):
		return summary
	summary["command"] = heap_info.get("command", "")
	summary["address"] = heap_info.get("address", "")
	output = ensure_text(heap_info.get("output", "")).strip()
	if output == "":
		if "error" in heap_info:
			summary["error"] = heap_info["error"]
		return summary
	summary_lines = []
	state_matches = []
	for raw_line in output.splitlines():
		line = raw_line.strip()
		if line == "":
			continue
		line_l = line.lower()
		summary_lines.append(line)
		for marker in ["busy", "free", "lfh", "virtalloc", "virtualalloc"]:
			if marker in line_l and marker not in state_matches:
				state_matches.append(marker)
		if "size" not in summary:
			size_match = re.search(r"\bsize\b[^0-9a-fA-F]*(0x[0-9a-fA-F]+|[0-9a-fA-F]+)", line, re.I)
			if size_match:
				summary["size"] = size_match.group(1)
		if "heap" not in summary:
			heap_match = re.search(r"\bheap\b[^0-9a-fA-F`]*(0x[0-9a-fA-F`]+|[0-9a-fA-F`]+)", line, re.I)
			if heap_match:
				summary["heap"] = heap_match.group(1).replace("`", "")
		if "user_pointer" not in summary:
			user_match = re.search(r"\b(?:user|block|address)\b[^0-9a-fA-F`]*(0x[0-9a-fA-F`]+|[0-9a-fA-F`]+)", line, re.I)
			if user_match:
				summary["user_pointer"] = user_match.group(1).replace("`", "")
	if len(state_matches) > 0:
		summary["state"] = ",".join(state_matches)
	if len(summary_lines) > 0:
		summary["summary_lines"] = summary_lines
		summary["output"] = output
	return summary


def _serializeReturnPointerEvidence(return_pointer):
	mndbg.dbgp(get_current_function_name())
	if not isinstance(return_pointer, dict):
		return return_pointer
	entry = OrderedDict()
	if "address" in return_pointer:
		entry["address"] = return_pointer["address"]
	if "symbol" in return_pointer:
		entry["symbol"] = return_pointer["symbol"]
	if "instruction_window" in return_pointer:
		window = return_pointer.get("instruction_window", {})
		if isinstance(window, dict):
			if "current" in window:
				entry["instruction"] = window.get("current", "")
			before = window.get("before", [])
			if isinstance(before, list) and len(before) > 0:
				entry["backward_disasm"] = before[-5:]
	return entry


def _compactHeapdynamicsContexts(heapdynamics):
	mndbg.dbgp(get_current_function_name())
	mini_contexts = []
	evidence = OrderedDict([
		("heap_blocks", []),
		("alloc_free_matches", [])
	])
	omitted_sections = []
	heap_block_ids = {}
	match_ids = {}
	heap_block_counter = 1
	match_counter = 1

	for info in heapdynamics:
		if not isinstance(info, dict):
			continue
		mini = OrderedDict()
		mini["instruction"] = info.get("instruction", "")
		mini["referenced_registers"] = info.get("referenced_registers", [])
		mini["source_file"] = info.get("file", "")
		mini["matched_registers"] = info.get("matched_registers", [])
		mini["matched_entries"] = []

		if "file_contents" in info and info.get("file_contents", "") != "":
			_appendOmittedSection(
				omitted_sections,
				"heapdynamics.file_contents",
				info.get("file_contents", ""),
				"full alloc/free log duplicated focused matches and exceeded size budget",
				"Use the original heapdynamics file at %s" % info.get("file", "")
			)

		for entry in info.get("matched_entries", []):
			match_key = "%s:%s:%s" % (
				info.get("file", ""),
				str(entry.get("line_number", 0)),
				ensure_text(entry.get("line", ""))
			)
			if match_key in match_ids:
				match_id = match_ids[match_key]
			else:
				match_id = "afm_%d" % match_counter
				match_counter += 1
				match_ids[match_key] = match_id
				match_evidence = OrderedDict()
				match_evidence["id"] = match_id
				match_evidence["source_file"] = info.get("file", "")
				match_evidence["line_number"] = entry.get("line_number", 0)
				match_evidence["line_excerpt"] = _formatContextText(entry.get("line", ""), max_len=512)
				match_evidence["matched_registers"] = entry.get("matched_registers", [])
				match_evidence["reason_for_inclusion"] = "alloc/free log line matched a register referenced by the crash instruction"
				context_window = []
				for context_line in entry.get("context_lines", []):
					context_window.append(OrderedDict([
						("line_number", context_line.get("line_number", 0)),
						("line", _formatContextText(context_line.get("line", ""), max_len=512)),
						("is_match", bool(context_line.get("is_match", False)))
					]))
				match_evidence["context_window"] = context_window
				if "return_pointer" in entry:
					match_evidence["return_pointer"] = _serializeReturnPointerEvidence(entry.get("return_pointer", {}))
				match_evidence["heap_block_refs"] = []
				evidence["alloc_free_matches"].append(match_evidence)

			for existing_match in evidence["alloc_free_matches"]:
				if existing_match.get("id", "") != match_id:
					continue
				for block_info in entry.get("heap_chunk_metadata", []):
					heap_info = block_info.get("heap", {})
					cache_key = "%s|%s|%s" % (
						heap_info.get("command", ""),
						heap_info.get("address", ""),
						ensure_text(heap_info.get("output", ""))
					)
					if cache_key in heap_block_ids:
						block_id = heap_block_ids[cache_key]
					else:
						block_id = "hb_%d" % heap_block_counter
						heap_block_counter += 1
						heap_block_ids[cache_key] = block_id
						block_evidence = OrderedDict()
						block_evidence["id"] = block_id
						block_evidence["register"] = block_info.get("register", "")
						block_evidence["value"] = block_info.get("value", "")
						for key, value in _summarizeHeapCommandOutput(heap_info).items():
							block_evidence[key] = value
						block_evidence["reason_for_inclusion"] = "heap block referenced by a register used by the crash instruction"
						evidence["heap_blocks"].append(block_evidence)
					if block_id not in existing_match["heap_block_refs"]:
						existing_match["heap_block_refs"].append(block_id)
				break

			mini["matched_entries"].append(OrderedDict([
				("evidence_id", match_id),
				("line_number", entry.get("line_number", 0)),
				("matched_registers", entry.get("matched_registers", []))
			]))
		mini_contexts.append(mini)

	return mini_contexts, evidence, omitted_sections


