def _extractTemplatePlaceholderNames(text_value):
	mndbg.dbgp(get_current_function_name())
	placeholder_names = set()
	for placeholder_name in re.findall(r"\[([A-Za-z0-9_]+)\]", ensure_text(text_value or "")):
		placeholder_names.add(placeholder_name.lower())
	return placeholder_names


def _loadTemplatePlaceholderNames(template_path):
	mndbg.dbgp(get_current_function_name())
	try:
		with open(template_path, "rb") as fh:
			template_text = fh.read().decode("latin-1")
	except Exception as e:
		raise RuntimeError("Unable to read template file '%s': %s" % (template_path, str(e)))
	prompt_block_text = _extractPromptBlockFromSavedRequestText(template_text)
	if prompt_block_text != "":
		template_text = prompt_block_text
	return _extractTemplatePlaceholderNames(template_text)


def _buildAIContextCollectionPlan(question_type="", requested_placeholders=None):
	mndbg.dbgp(get_current_function_name())
	placeholder_names = set([ensure_text(name).strip().lower() for name in (requested_placeholders or set()) if ensure_text(name).strip() != ""])
	plan = OrderedDict([
		("include_instruction_heap_context", False),
		("include_heap_details", False),
		("include_findmsp", False),
		("include_modules", False),
		("include_pc_context", False),
		("include_heapdynamics", False),
		("include_stack_context", False),
		("include_ntglobal_flag", False),
		("include_seh_chain", False),
		("include_call_stack", False),
		("include_windbg_analyze", False),
	])

	if question_type == "1":
		for key in plan:
			plan[key] = True
	elif question_type == "2":
		plan["include_modules"] = True
	elif question_type in ["3", "3b"]:
		for key in [
			"include_instruction_heap_context",
			"include_heap_details",
			"include_modules",
			"include_pc_context",
			"include_heapdynamics",
			"include_stack_context",
			"include_call_stack",
		]:
			plan[key] = True
	elif question_type == "8":
		plan["include_modules"] = False

	if len(placeholder_names & _TEMPLATE_CRASH_PLACEHOLDERS) > 0:
		for key in [
			"include_instruction_heap_context",
			"include_heap_details",
			"include_findmsp",
			"include_modules",
			"include_pc_context",
			"include_heapdynamics",
			"include_stack_context",
			"include_ntglobal_flag",
			"include_seh_chain",
			"include_call_stack",
			"include_windbg_analyze",
		]:
			plan[key] = True
	if len(placeholder_names & _TEMPLATE_FUNCTION_PLACEHOLDERS) > 0:
		plan["include_modules"] = True
	if len(placeholder_names & _TEMPLATE_CONTROLLED_DATA_PLACEHOLDERS) > 0:
		for key in [
			"include_instruction_heap_context",
			"include_heap_details",
			"include_modules",
			"include_pc_context",
			"include_heapdynamics",
			"include_stack_context",
			"include_call_stack",
		]:
			plan[key] = True
	return plan


def _serializeModuleSummaryForTellme(mod):
	mndbg.dbgp(get_current_function_name())
	if mod is None:
		return OrderedDict()
	info = OrderedDict()
	info["name"] = mod.moduleFilename or mod.moduleKey
	info["key"] = mod.moduleKey
	info["path"] = mod.modulePath
	info["base"] = PTR_PRINT % mod.moduleBase
	info["top"] = PTR_PRINT % mod.moduleTop
	info["size"] = "0x%x" % mod.moduleSize
	info["rebase"] = mod.isRebase
	info["aslr"] = mod.isAslr
	info["safeseh"] = mod.isSafeSEH
	info["cfg"] = mod.isCFG
	return info

def _collectRelevantModuleAddresses(context):
	mndbg.dbgp(get_current_function_name())
	addresses = []
	seen = set()

	def _add_address(value):
		if not isinstance(value, int) or value <= 0 or value in seen:
			return
		seen.add(value)
		addresses.append(value)

	try:
		regs = getAllRegisters()
	except Exception:
		regs = {}
	_add_address(regs.get(PROGRAM_COUNTER, 0))
	_add_address(regs.get(STACK_POINTER, 0))

	seh_chain = context.get("seh_chain", {})
	if isinstance(seh_chain, dict):
		for record in seh_chain.get("records", []):
			handler = _tryParseAddressToken(record.get("handler", ""))
			_add_address(handler)

	heapdynamics = context.get("heapdynamics", [])
	for file_info in heapdynamics:
		for entry in file_info.get("matched_entries", []):
			return_pointer = entry.get("return_pointer", {})
			_add_address(_tryParseAddressToken(return_pointer.get("address", "")))

	return addresses


def _buildCompactModulesSummary(context):
	mndbg.dbgp(get_current_function_name())
	if mnproc is None:
		return "Unable to resolve current process context"
	result = OrderedDict()
	all_modules = sorted(mnproc.getPEB().getModules().values(), key=lambda mod: mod.moduleBase)
	result["total_loaded_modules"] = len(all_modules)

	process_name = ensure_text(context.get("processname", "")).strip().lower()
	process_basename = os.path.basename(process_name)
	executable_module = None
	pc_module = None
	relevant_module_names = []
	relevant_seen = set()

	def _add_relevant_module(mod):
		if mod is None:
			return
		module_key = ensure_text(mod.moduleKey).lower()
		if module_key in relevant_seen:
			return
		relevant_seen.add(module_key)
		relevant_module_names.append(mod.moduleFilename or mod.moduleKey)

	for address in _collectRelevantModuleAddresses(context):
		mod = mnproc.getModuleForAddress(address)
		if mod is None:
			continue
		if pc_module is None and address == getAllRegisters().get(PROGRAM_COUNTER, 0):
			pc_module = mod
		_add_relevant_module(mod)

	for mod in all_modules:
		if executable_module is None:
			mod_names = [ensure_text(mod.moduleKey).lower(), ensure_text(mod.moduleFilename).lower()]
			mod_path = ensure_text(mod.modulePath).lower()
			if process_name != "" and (process_name == mod_path or process_basename in mod_names):
				executable_module = mod
		if (not mod.isAslr) or (not mod.isSafeSEH) or (not mod.isCFG):
			_add_relevant_module(mod)

	if pc_module is None:
		pc_module = mnproc.getModuleForAddress(getAllRegisters().get(PROGRAM_COUNTER, 0))
	if pc_module is not None:
		result["pc_module_name"] = pc_module.moduleFilename or pc_module.moduleKey
	if executable_module is not None:
		result["executable_module_name"] = executable_module.moduleFilename or executable_module.moduleKey

	result["relevant_module_names"] = relevant_module_names[:32]
	if len(relevant_module_names) > 32:
		result["relevant_module_names_truncated"] = True
	return result


def _optimizeQ1RequestVariables(context, maxsize_kb=0):
	mndbg.dbgp(get_current_function_name())
	variables = _buildRequestVariables(context)
	omitted_sections = []

	if "windbg_analyze" in variables:
		original_analyze = variables.get("windbg_analyze", {})
		variables["windbg_analyze_full"] = original_analyze
		variables["windbg_analyze"] = _simplifyWindbgAnalyze(original_analyze)
		if "windbg_analyze_mini" in variables:
			del variables["windbg_analyze_mini"]

	if "modules" in variables:
		original_modules = variables.get("modules", "")
		variables["modules_full"] = original_modules
		variables["modules"] = _buildCompactModulesSummary(context)
		if "modules_mini" in variables:
			del variables["modules_mini"]

	if "heapdynamics" in variables:
		heapdynamics = variables.get("heapdynamics", [])
		mini_contexts, evidence, heap_omissions = _compactHeapdynamicsContexts(heapdynamics)
		variables["heapdynamics_full"] = heapdynamics
		variables["heapdynamics"] = mini_contexts
		if "heapdynamics_mini" in variables:
			del variables["heapdynamics_mini"]
		variables["evidence"] = evidence
		omitted_sections.extend(heap_omissions)
	elif "heapdynamics_mini" in variables:
		del variables["heapdynamics_mini"]

	for redundant_key in ["modules_mini", "heapdynamics_mini", "windbg_analyze_mini"]:
		if redundant_key in variables:
			del variables[redundant_key]

	variables["size_budget"] = OrderedDict([
		("requested_max_kb", int(maxsize_kb) if isinstance(maxsize_kb, int) and maxsize_kb > 0 else 0),
		("requested_max_bytes", (int(maxsize_kb) * 1024) if isinstance(maxsize_kb, int) and maxsize_kb > 0 else 0)
	])

	size_budget = 0
	if isinstance(maxsize_kb, int) and maxsize_kb > 0:
		size_budget = maxsize_kb * 1024
		trim_candidates = [
			("heapdynamics_full", "full heapdynamics context exceeded the requested -maxsize budget; focused matches were kept under heapdynamics", "Use the original heapdynamics file path recorded under heapdynamics.source_file"),
			("modules_full", "full module listing exceeded the requested -maxsize budget; crash-focused module summary was kept under modules", "Run the modules command or use tellme -q 3 for broader module analysis"),
			("windbg_analyze_full", "full !analyze -v output exceeded the requested -maxsize budget; structured crash fields were kept under windbg_analyze", "Run !analyze -v in WinDBG to retrieve the full text"),
			("additional_context_files", "additional context file contents exceeded the requested -maxsize budget", "Use the original file(s) supplied with -l"),
			("poc_file", "PoC file contents exceeded the requested -maxsize budget", "Use the original PoC file supplied with -p"),
			("heap_details", "heap_details duplicated more focused heap evidence and exceeded the requested -maxsize budget", "Re-run heap commands manually for full heap enumeration"),
			("pc_memory", "pc_memory exceeded the requested -maxsize budget after higher-value evidence was kept", "Use db/dd/dq on the program counter manually for the full window"),
		]
		for key, reason, retrieval_hint in trim_candidates:
			if _getJsonSizeBytes(variables) <= size_budget:
				break
			if key not in variables or variables.get(key, "") in ["", [], {}]:
				continue
			original_value = variables[key]
			variables[key] = ""
			_appendOmittedSection(omitted_sections, key, original_value, reason, retrieval_hint)

	if len(omitted_sections) > 0:
		variables["omitted_sections"] = omitted_sections
	else:
		variables["omitted_sections"] = []
	variables["size_budget"]["final_size_bytes"] = _getJsonSizeBytes(variables)
	variables["size_budget"]["final_size_kb"] = round(float(variables["size_budget"]["final_size_bytes"]) / 1024.0, 2)
	variables["size_budget"]["maxsize_enforced"] = (size_budget > 0)
	variables["size_budget"]["within_requested_max"] = (size_budget <= 0 or variables["size_budget"]["final_size_bytes"] <= size_budget)

	return variables


def _safeTextValue(value):
	mndbg.dbgp(get_current_function_name())
	if value is None:
		return ""
	if isinstance(value, bytes):
		try:
			return value.decode("latin-1", "replace")
		except Exception:
			return repr(value)
	try:
		return str(value)
	except Exception:
		return ""


def _getUniqueControlFlowDisasmRef(base_ref, control_flow_disasm, control_flow_disasm_map):
	mndbg.dbgp(get_current_function_name())
	ref_value = _safeTextValue(base_ref).strip()
	if ref_value == "":
		ref_value = "control_flow_disasm"
	if ref_value not in control_flow_disasm_map:
		return ref_value
	existing_entry = control_flow_disasm_map.get(ref_value, {})
	if isinstance(existing_entry, dict):
		existing_disasm = _safeTextValue(existing_entry.get("disasm", "")).strip()
		if existing_disasm == control_flow_disasm:
			return ref_value
	suffix = 2
	while True:
		candidate = "%s#%d" % (ref_value, suffix)
		if candidate not in control_flow_disasm_map:
			return candidate
		existing_entry = control_flow_disasm_map.get(candidate, {})
		if isinstance(existing_entry, dict):
			existing_disasm = _safeTextValue(existing_entry.get("disasm", "")).strip()
			if existing_disasm == control_flow_disasm:
				return candidate
		suffix += 1


def _registerQ3ControlFlowDisasm(target_entry, control_flow_disasm, seen_control_flow_disasm, control_flow_disasm_map):
	mndbg.dbgp(get_current_function_name())
	control_flow_disasm = _safeTextValue(control_flow_disasm).strip()
	if control_flow_disasm == "":
		return ""
	full_function_disasm = _safeTextValue(target_entry.get("control_flow_full_function_disasm", "")).strip()
	canonical_disasm = full_function_disasm
	if canonical_disasm == "":
		canonical_disasm = control_flow_disasm
	if canonical_disasm in seen_control_flow_disasm:
		return seen_control_flow_disasm[canonical_disasm]
	target_address_text = _safeTextValue(target_entry.get("target_address_text", "")).strip()
	control_flow_function_start = _safeTextValue(target_entry.get("control_flow_function_start", "")).strip()
	symbol = _safeTextValue(target_entry.get("symbol", "")).strip()
	base_ref = control_flow_function_start
	if base_ref == "":
		base_ref = target_address_text
	if base_ref == "":
		base_ref = control_flow_function_start
	if base_ref == "":
		base_ref = symbol
	ref_value = _getUniqueControlFlowDisasmRef(base_ref, canonical_disasm, control_flow_disasm_map)
	control_flow_entry = OrderedDict([
		("address", ref_value),
		("symbol", symbol),
		("scope", "function" if full_function_disasm != "" else _safeTextValue(target_entry.get("control_flow_scope", "")).strip()),
		("function_start", control_flow_function_start),
		("disasm", canonical_disasm),
	])
	control_flow_disasm_map[ref_value] = control_flow_entry
	seen_control_flow_disasm[canonical_disasm] = ref_value
	return ref_value


def _getUniqueControlFlowTargetRef(base_ref, target_entry, control_flow_target_map):
	mndbg.dbgp(get_current_function_name())
	ref_value = _safeTextValue(base_ref).strip()
	if ref_value == "":
		ref_value = "control_flow_target"
	target_signature = json.dumps(target_entry, sort_keys=True)
	if ref_value not in control_flow_target_map:
		return ref_value
	existing_entry = control_flow_target_map.get(ref_value, {})
	if isinstance(existing_entry, dict):
		existing_signature = json.dumps(existing_entry, sort_keys=True)
		if existing_signature == target_signature:
			return ref_value
	suffix = 2
	while True:
		candidate = "%s#%d" % (ref_value, suffix)
		if candidate not in control_flow_target_map:
			return candidate
		existing_entry = control_flow_target_map.get(candidate, {})
		if isinstance(existing_entry, dict):
			existing_signature = json.dumps(existing_entry, sort_keys=True)
			if existing_signature == target_signature:
				return candidate
		suffix += 1


def _registerQ3TargetEntry(target_entry, seen_control_flow_disasm, control_flow_disasm_map, seen_control_flow_targets, control_flow_target_map):
	mndbg.dbgp(get_current_function_name())
	if not isinstance(target_entry, dict):
		return ""
	working_entry = copy.deepcopy(target_entry)
	nested_targets = working_entry.get("nested_control_flow_targets", [])
	nested_target_refs = []
	if isinstance(nested_targets, list) and len(nested_targets) > 0:
		nested_target_refs = _compactQ3TargetEntries(
			nested_targets,
			seen_control_flow_disasm,
			control_flow_disasm_map,
			seen_control_flow_targets,
			control_flow_target_map
		)
	control_flow_disasm = _safeTextValue(working_entry.get("control_flow_disasm", "")).strip()
	full_function_disasm = _safeTextValue(working_entry.get("control_flow_full_function_disasm", "")).strip()
	disasm_preview = _safeTextValue(working_entry.get("disasm", "")).strip()
	disasm_for_registration = control_flow_disasm
	if disasm_for_registration == "" and full_function_disasm != "":
		disasm_for_registration = full_function_disasm
	if disasm_for_registration != "":
		working_entry["control_flow_disasm_ref"] = _registerQ3ControlFlowDisasm(
			working_entry,
			disasm_for_registration,
			seen_control_flow_disasm,
			control_flow_disasm_map
		)
		working_entry["control_flow_disasm"] = ""
		working_entry["disasm"] = ""
		if "disasm_preview" in working_entry:
			del working_entry["disasm_preview"]
	elif disasm_preview != "":
		working_entry["disasm_preview"] = disasm_preview
	working_entry["nested_control_flow_target_refs"] = nested_target_refs
	working_entry["nested_control_flow_targets"] = []
	working_entry["control_flow_full_function_disasm"] = ""
	target_signature = json.dumps(working_entry, sort_keys=True)
	if target_signature in seen_control_flow_targets:
		return seen_control_flow_targets[target_signature]
	base_ref = _safeTextValue(working_entry.get("instruction_address", "")).strip()
	if base_ref == "":
		base_ref = _safeTextValue(working_entry.get("target_address_text", "")).strip()
	if base_ref == "":
		base_ref = _safeTextValue(working_entry.get("symbol", "")).strip()
	ref_value = _getUniqueControlFlowTargetRef(base_ref, working_entry, control_flow_target_map)
	control_flow_target_map[ref_value] = working_entry
	seen_control_flow_targets[target_signature] = ref_value
	return ref_value


def _compactQ3TargetEntries(target_entries, seen_control_flow_disasm, control_flow_disasm_map, seen_control_flow_targets, control_flow_target_map):
	mndbg.dbgp(get_current_function_name())
	target_refs = []
	if not isinstance(target_entries, list):
		return target_refs
	for target_entry in target_entries:
		target_ref = _registerQ3TargetEntry(
			target_entry,
			seen_control_flow_disasm,
			control_flow_disasm_map,
			seen_control_flow_targets,
			control_flow_target_map
		)
		if target_ref != "":
			target_refs.append(target_ref)
	del target_entries[:]
	return target_refs


def _compactQ3TargetContainer(container, seen_control_flow_disasm, control_flow_disasm_map, seen_control_flow_targets, control_flow_target_map):
	mndbg.dbgp(get_current_function_name())
	if not isinstance(container, dict):
		return
	target_entries = container.get("control_flow_targets", [])
	if isinstance(target_entries, list) and len(target_entries) > 0:
		container["control_flow_target_refs"] = _compactQ3TargetEntries(
			target_entries,
			seen_control_flow_disasm,
			control_flow_disasm_map,
			seen_control_flow_targets,
			control_flow_target_map
		)
		container["control_flow_targets"] = []


def _compactQ3FunctionContext(function_context, seen_control_flow_disasm, control_flow_disasm_map, seen_control_flow_targets, control_flow_target_map, preserve_full_uf=False):
	mndbg.dbgp(get_current_function_name())
	if not isinstance(function_context, dict):
		return
	uf_output = _safeTextValue(function_context.get("uf_output", "")).strip()
	if preserve_full_uf:
		if uf_output != "":
			ref_value = _safeTextValue(function_context.get("requested_address", "")).strip()
			if ref_value == "":
				ref_value = _safeTextValue(function_context.get("function_start", "")).strip()
			if ref_value != "":
				seen_control_flow_disasm[uf_output] = ref_value
	else:
		if uf_output != "":
			if uf_output in seen_control_flow_disasm:
				function_context["uf_output_ref"] = seen_control_flow_disasm[uf_output]
				function_context["uf_output"] = ""
			else:
				ref_value = _safeTextValue(function_context.get("requested_address", "")).strip()
				if ref_value == "":
					ref_value = _safeTextValue(function_context.get("function_start", "")).strip()
				if ref_value != "":
					seen_control_flow_disasm[uf_output] = ref_value
	if function_context.get("analysis_scope", "") == "function":
		function_context["code_before"] = ""
		if not bool(function_context.get("forward_flow_from_requested_address", False)):
			function_context["code_after"] = ""
	_compactQ3TargetContainer(
		function_context,
		seen_control_flow_disasm,
		control_flow_disasm_map,
		seen_control_flow_targets,
		control_flow_target_map
	)


def _resolveQ3TargetEntries(target_entries, control_flow_target_map=None, target_refs=None):
	mndbg.dbgp(get_current_function_name())
	if isinstance(target_entries, list) and len(target_entries) > 0:
		return target_entries
	resolved = []
	if not isinstance(target_refs, list) or not isinstance(control_flow_target_map, dict):
		return resolved
	for target_ref in target_refs:
		target_ref = _safeTextValue(target_ref).strip()
		if target_ref == "":
			continue
		target_entry = control_flow_target_map.get(target_ref, {})
		if isinstance(target_entry, dict) and len(target_entry) > 0:
			resolved.append(target_entry)
	return resolved


def _summarizeQ3TargetEntries(target_entries, max_entries=12, control_flow_target_map=None, target_refs=None):
	mndbg.dbgp(get_current_function_name())
	summaries = []
	target_entries = _resolveQ3TargetEntries(target_entries, control_flow_target_map=control_flow_target_map, target_refs=target_refs)
	if not isinstance(target_entries, list):
		return summaries
	entry_count = 0
	for target_entry in target_entries:
		interruptMona()
		if not isinstance(target_entry, dict):
			continue
		entry_count += 1
		if entry_count > max_entries:
			break
		summary = OrderedDict()
		for key in [
			"kind",
			"instruction_address",
			"instruction",
			"target_operand",
			"resolved",
			"target_address_text",
			"symbol",
			"follow_depth",
			"resolution_reason"
		]:
			if key in target_entry and target_entry.get(key, "") != "":
				summary[key] = target_entry.get(key)
		nested_targets = _resolveQ3TargetEntries(
			target_entry.get("nested_control_flow_targets", []),
			control_flow_target_map=control_flow_target_map,
			target_refs=target_entry.get("nested_control_flow_target_refs", [])
		)
		if isinstance(nested_targets, list) and len(nested_targets) > 0:
			summary["nested_target_count"] = len(nested_targets)
		summaries.append(summary)
	return summaries


def _summarizeCallerFunctionContext(function_context):
	mndbg.dbgp(get_current_function_name())
	summary = OrderedDict()
	if not isinstance(function_context, dict):
		return summary
	for key in [
		"requested_address",
		"symbol",
		"analysis_scope",
		"function_start",
		"offset_from_function_start",
		"control_flow_follow_depth",
		"uf_output_ref"
	]:
		if key in function_context and function_context.get(key, "") != "":
			summary[key] = function_context.get(key)
	uf_output = ensure_text(function_context.get("uf_output", "")).strip()
	if uf_output != "":
		summary["uf_output_lines"] = len([line for line in uf_output.splitlines() if ensure_text(line).strip() != ""])
	return summary


def _summarizeCallerResumeWindow(window, control_flow_target_map=None):
	mndbg.dbgp(get_current_function_name())
	summary = OrderedDict()
	if not isinstance(window, dict):
		return summary
	for key in ["address", "current"]:
		if key in window and window.get(key, "") != "":
			summary[key] = window.get(key)
	after = window.get("after", [])
	if isinstance(after, list) and len(after) > 0:
		summary["after_preview"] = after[:8]
	forward_disasm = ensure_text(window.get("forward_disasm", "")).strip()
	if forward_disasm != "":
		summary["forward_disasm_lines"] = len([line for line in forward_disasm.splitlines() if ensure_text(line).strip() != ""])
	control_flow_targets = _resolveQ3TargetEntries(
		window.get("control_flow_targets", []),
		control_flow_target_map=control_flow_target_map,
		target_refs=window.get("control_flow_target_refs", [])
	)
	if isinstance(control_flow_targets, list) and len(control_flow_targets) > 0:
		summary["branch_targets"] = _summarizeQ3TargetEntries(
			control_flow_targets,
			max_entries=12,
			control_flow_target_map=control_flow_target_map
		)
		indirect_transfers = []
		_collectIndirectTransfersFromTargets(
			control_flow_targets,
			indirect_transfers,
			path_class="return-resume",
			control_flow_target_map=control_flow_target_map
		)
		if len(indirect_transfers) > 0:
			summary["indirect_transfers"] = indirect_transfers[:12]
	return summary


def _buildCompactReturnResumeAnalysisForRequest(variables, control_flow_target_map=None):
	mndbg.dbgp(get_current_function_name())
	summary = OrderedDict()
	if not isinstance(variables, dict):
		return summary
	return_resume_analysis = variables.get("return_resume_analysis", {})
	if not isinstance(return_resume_analysis, dict):
		return summary
	for key in ["retaddr", "caller"]:
		if key in return_resume_analysis and return_resume_analysis.get(key, "") != "":
			summary[key] = return_resume_analysis.get(key)
	return_context = variables.get("return_context", {})
	if isinstance(return_context, dict) and len(return_context) > 0:
		summary["return_context"] = return_context
	caller_function = variables.get("caller_function", {})
	if isinstance(caller_function, dict) and len(caller_function) > 0:
		summary["caller_function"] = caller_function
	caller_resume_window = variables.get("caller_resume_window", {})
	if isinstance(caller_resume_window, dict) and len(caller_resume_window) > 0:
		summary["resume_window"] = _summarizeCallerResumeWindow(caller_resume_window, control_flow_target_map=control_flow_target_map)
	post_constraints = variables.get("post_return_constraints", {})
	if isinstance(post_constraints, dict) and len(post_constraints) > 0:
		summary["post_return_constraints"] = post_constraints
	caller_chain = variables.get("caller_chain", [])
	if isinstance(caller_chain, list) and len(caller_chain) > 0:
		summary["caller_chain_frame_count"] = len(caller_chain)
	return summary


def _buildCompactCallerChainForRequest(caller_chain, control_flow_target_map=None):
	mndbg.dbgp(get_current_function_name())
	compact_chain = []
	if not isinstance(caller_chain, list):
		return compact_chain
	for frame_entry in caller_chain:
		interruptMona()
		if not isinstance(frame_entry, dict):
			continue
		compact_entry = OrderedDict()
		compact_entry["frame_index"] = frame_entry.get("frame_index", "")
		return_context = frame_entry.get("return_context", {})
		if isinstance(return_context, dict) and len(return_context) > 0:
			compact_entry["return_context"] = return_context
		caller_function = frame_entry.get("caller_function", {})
		if isinstance(caller_function, dict) and len(caller_function) > 0:
			compact_entry["caller_function"] = caller_function
		caller_resume_window = frame_entry.get("caller_resume_window", {})
		if isinstance(caller_resume_window, dict) and len(caller_resume_window) > 0:
			compact_entry["caller_resume_window"] = _summarizeCallerResumeWindow(caller_resume_window, control_flow_target_map=control_flow_target_map)
		post_constraints = frame_entry.get("post_return_constraints", {})
		if isinstance(post_constraints, dict) and len(post_constraints) > 0:
			compact_entry["post_return_constraints"] = post_constraints
		compact_chain.append(compact_entry)
	return compact_chain


def _optimizeQ3RequestVariables(context, maxsize_kb=0):
	mndbg.dbgp(get_current_function_name())
	variables = _buildRequestVariables(context)
	seen_control_flow_disasm = {}
	control_flow_disasm_map = OrderedDict()
	seen_control_flow_targets = {}
	control_flow_target_map = OrderedDict()
	if "current_function" in variables and isinstance(variables.get("current_function"), dict):
		_compactQ3FunctionContext(variables["current_function"], seen_control_flow_disasm, control_flow_disasm_map, seen_control_flow_targets, control_flow_target_map, preserve_full_uf=True)
	if "target_function" in variables and isinstance(variables.get("target_function"), dict):
		_compactQ3FunctionContext(variables["target_function"], seen_control_flow_disasm, control_flow_disasm_map, seen_control_flow_targets, control_flow_target_map, preserve_full_uf=False)
	if "caller_function" in variables and isinstance(variables.get("caller_function"), dict):
		_compactQ3FunctionContext(variables["caller_function"], seen_control_flow_disasm, control_flow_disasm_map, seen_control_flow_targets, control_flow_target_map, preserve_full_uf=True)
	if "caller_resume_window" in variables and isinstance(variables.get("caller_resume_window"), dict):
		_compactQ3TargetContainer(variables["caller_resume_window"], seen_control_flow_disasm, control_flow_disasm_map, seen_control_flow_targets, control_flow_target_map)
	if "caller_chain" in variables and isinstance(variables.get("caller_chain"), list):
		for frame_entry in variables["caller_chain"]:
			if not isinstance(frame_entry, dict):
				continue
			caller_func = frame_entry.get("caller_function", {})
			if isinstance(caller_func, dict):
				_compactQ3FunctionContext(caller_func, seen_control_flow_disasm, control_flow_disasm_map, seen_control_flow_targets, control_flow_target_map, preserve_full_uf=True)
			caller_resume_window = frame_entry.get("caller_resume_window", {})
			if isinstance(caller_resume_window, dict):
				_compactQ3TargetContainer(caller_resume_window, seen_control_flow_disasm, control_flow_disasm_map, seen_control_flow_targets, control_flow_target_map)
		variables["caller_chain"] = _buildCompactCallerChainForRequest(variables["caller_chain"], control_flow_target_map=control_flow_target_map)
	if "return_resume_analysis" in variables and isinstance(variables.get("return_resume_analysis"), dict):
		variables["return_resume_analysis"] = _buildCompactReturnResumeAnalysisForRequest(variables, control_flow_target_map=control_flow_target_map)
	if len(control_flow_disasm_map) > 0:
		variables["control_flow_disasm_map"] = control_flow_disasm_map
	if len(control_flow_target_map) > 0:
		variables["control_flow_target_map"] = control_flow_target_map
	return variables


def _pruneEmptyRequestValues(value):
	mndbg.dbgp(get_current_function_name())
	if isinstance(value, dict):
		pruned = OrderedDict() if isinstance(value, OrderedDict) else {}
		for key, child_value in value.items():
			pruned_child = _pruneEmptyRequestValues(child_value)
			if pruned_child in [None, "", [], {}]:
				continue
			if isinstance(pruned_child, OrderedDict) and len(pruned_child) == 0:
				continue
			pruned[key] = pruned_child
		return pruned
	if isinstance(value, list):
		pruned_list = []
		for child_value in value:
			pruned_child = _pruneEmptyRequestValues(child_value)
			if pruned_child in [None, "", [], {}]:
				continue
			if isinstance(pruned_child, OrderedDict) and len(pruned_child) == 0:
				continue
			pruned_list.append(pruned_child)
		return pruned_list
	return value


def _buildRequestVariables(context):
	mndbg.dbgp(get_current_function_name())
	variables = OrderedDict()
	preferred_keys = [
		"debugger",
		"debugger_flavor",
		"processname",
		"modules",
		"modules_mini",
		"modules_full",
		"architecture",
		"pointer_size",
		"python_version",
		"timestamp",
		"registers",
		"program_counter",
		"stack_pointer",
		"pc_disasm",
		"pc_page",
		"pc_module",
		"pc_memory",
		"stack_page",
		"stack_memory",
		"ntglobal_flag",
		"seh_chain",
		"findmsp",
		"findseh",
		"call_stack",
		"windbg_analyze",
		"windbg_analyze_mini",
		"windbg_analyze_full",
		"instruction_heap_references",
		"heap_details",
		"heapdynamics",
		"heapdynamics_mini",
		"heapdynamics_full",
		"evidence",
		"size_budget",
		"omitted_sections",
		"additional_context_files",
		"poc_file",
		"heap_analysis_target",
		"analysis_target",
		"current_function",
		"additional_function",
		"additional_function_note",
		"function_analyses",
		"q3_goal",
		"reachability_target",
		"controlled_chunk",
		"controlled_chunk_references",
		"target_function",
		"return_context",
		"return_resume_analysis",
		"controlled_object_callees",
		"control_flow_disasm_map",
		"control_flow_target_map",
		"caller_function",
		"caller_chain",
		"caller_resume_window",
		"post_return_constraints",
		"reachable_functions",
		"rop_target_modules",
	]
	for key in preferred_keys:
		if key in context:
			variables[key] = context[key]
		else:
			variables[key] = ""
	for key in context:
		if key not in variables:
			variables[key] = context[key]
	return variables


def _buildTemplateRequestVariables(context, requested_placeholders=None, question_type="", maxsize_kb=0):
	mndbg.dbgp(get_current_function_name())
	placeholder_names = set([ensure_text(name).strip().lower() for name in (requested_placeholders or set()) if ensure_text(name).strip() != ""])
	variables = _buildRequestVariables(context)
	crash_view_placeholders = set([
		"evidence",
		"findmsp",
		"findseh",
		"heap_analysis_target",
		"heap_details",
		"heapdynamics",
		"heapdynamics_full",
		"heapdynamics_mini",
		"instruction_heap_references",
		"modules_mini",
		"ntglobal_flag",
		"omitted_sections",
		"seh_chain",
		"size_budget",
		"windbg_analyze",
		"windbg_analyze_full",
		"windbg_analyze_mini",
	])
	include_crash_view = question_type == "1" or len(placeholder_names & crash_view_placeholders) > 0
	include_controlled_data_view = question_type in ["3", "3b"] or len(placeholder_names & _TEMPLATE_CONTROLLED_DATA_PLACEHOLDERS) > 0
	if include_crash_view:
		variables.update(_optimizeQ1RequestVariables(context, maxsize_kb=maxsize_kb))
		if "modules" in variables and "modules_mini" not in variables:
			variables["modules_mini"] = variables["modules"]
		if "windbg_analyze" in variables and "windbg_analyze_mini" not in variables:
			variables["windbg_analyze_mini"] = variables["windbg_analyze"]
		if "heapdynamics" in variables and "heapdynamics_mini" not in variables:
			variables["heapdynamics_mini"] = variables["heapdynamics"]
	if include_controlled_data_view:
		variables.update(_optimizeQ3RequestVariables(context, maxsize_kb=maxsize_kb))
	return _pruneEmptyRequestValues(variables)


def _buildRequestPayload(mode, question_type, variables, template_text="", template_file=""):
	mndbg.dbgp(get_current_function_name())
	request_payload = OrderedDict()
	request_payload["mode"] = mode
	request_payload["question_type"] = question_type
	if template_file != "":
		request_payload["template_file"] = template_file
	if template_text != "":
		request_payload["template"] = template_text
	request_payload["variables"] = variables
	return request_payload


