def getSegmentEnd(segmentstart):
	#os = dbg.getOsVersion()
	offset = 0x24
	if g_win7_mode:
		offset = 0x28
	segmentend = struct.unpack(PTR_FMT,dbg.readMemory(segmentstart + offset,PTR_SIZE))[0]
	return segmentend


def getHeapFlag(flag):
	flags = {
	0x0 : "Free",
	0x1 : "Busy",
	0x2 : "Extra present",
	0x4 : "Fill pattern",
	0x8 : "Virtallocd",
	0x10 : "Last",
	0x20 : "Internal/FFU-1",
	0x40 : "Internal/FFU-2",
	0x80 : "Internal/No Coalesce"
	}
	#if g_win7_mode:
	#	flags[0x8] = "Internal"
	if flag in flags:
		return flags[flag]
	else:
		# maybe it's a combination of flags
		values = [0x80, 0x40, 0x20, 0x10, 0x8, 0x4, 0x2, 0x1]
		flagtext = []
		for val in values:
			if (flag - val) >= 0:
				flagtext.append(flags[val])
				flag -= val
		if len(flagtext) == 0:
			flagtext = "Unknown"
		else:
			flagtext = ','.join(flagtext)
		return flagtext

def decodeHeapHeader(headeraddress, headersize, key):
	# Read all bytes at once and XOR the first 8 (key size) with the encoding key.
	raw = bytearray(dbg.readMemory(headeraddress, headersize))
	for i in range(min(8, headersize)):
		raw[i] ^= (key >> (i * 8)) & 0xFF
	return bytes(raw)

def walkSegment(FirstEntry,LastValidEntry,heapbase):
	"""
	Finds all chunks in a given segment

	Arguments : Start and End of segment, and heapbase

	Returns a dictionary of MnChunk objects
	Key : chunk pointer

	"""
	mSegment = MnSegment(heapbase,FirstEntry,LastValidEntry)
	return mSegment.walk()

	
def getStacks():
	"""
	Retrieves all stacks from all threads in the current application

	Arguments:
	None

	Return:
	a dictionary, with key = threadID. Each entry contains an array with base and top of the stack
	"""
	MnProc.ensure()
	mnproc.getThreads()
	if len(mnproc.stacklistCache) > 0:
		return mnproc.stacklistCache
	stacks = {}
	for tid, teb in mnproc.getThreads().items():
		stacks[tid] = [teb.StackLimit, teb.StackBase]
	mnproc.stacklistCache = stacks
	return stacks

def meetsAccessLevel(page,accessLevel):
	"""
	Checks if a given page meets a given access level

	Arguments:
	page - a page object
	accesslevel - a string containing one of the following access levels :
	R,W,X,RW,RX,WR,WX,RWX or *

	Return:
	a boolean
	"""
	if "*" in accessLevel:
		return True
	
	pageAccess = page.getAccess(human=True)
	
	if "-R" in accessLevel:
		if "READ" in pageAccess:
			return False
	if "-W" in accessLevel:
		if "WRITE" in pageAccess:
			return False
	if "-X" in accessLevel:
		if "EXECUTE" in pageAccess:
			return False
	if "R" in accessLevel:
		if not "READ" in pageAccess:
			return False
	if "W" in accessLevel:
		if not "WRITE" in pageAccess:
			return False
	if "X" in accessLevel:
		if not "EXECUTE" in pageAccess:
			return False
			
	return True

def splitToPtrInstr(input):
	"""
	Splits a line (retrieved from a mona output file) into a pointer and a string with the instructions in the file

	Arguments:
	input : the line containing pointer and instruction

	Return:
	a pointer - (integer value)
	a string - instruction
	if the input does not contain a valid line, pointer will be set to -1 and string will be empty
	"""	
	
	thispointer = -1
	thisinstruction = ""

	if isinstance(input, bytes):
		input = input.decode("latin-1", errors="ignore")
	
	# Some mona output lines may be indented; don't require the pointer to be at column 0.
	thisline = input.lower()
	thisline_stripped = thisline.lstrip()
	input_stripped = input.lstrip()
	
	# Skip comment lines and lines without instruction separator
	if thisline_stripped.startswith("#"):
		return thispointer, thisinstruction
	# Gadget/instruction lines use " : " (space-colon-space) as separator.
	if " : " not in input_stripped:
		return thispointer, thisinstruction
	
	split1 = re.compile(" ")
	split2 = re.compile(":")
	split3 = re.compile(r"\*\*")
	startswith_arg = "0x"
	newline_arg = "\n"
	carriage_arg = "\r"
	colon_arg = ":"
	ptr_re = re.compile(r"^0x[0-9a-f]{8,16}$")
	
	if thisline_stripped.startswith(startswith_arg):
		#get the pointer
		parts = split1.split(input_stripped)
		#mndbg.dbgp("Parts: %s" % parts)
		part1 = parts[0].replace(newline_arg, "").replace(carriage_arg, "")
		part1_lc = part1.lower()
		# Accept both 32-bit (8 hex digits) and 64-bit (up to 16 hex digits) pointers.
		if not ptr_re.match(part1_lc):
			return thispointer, thisinstruction
		else:
			thispointer = hexStrToInt(part1)
			if len(parts) > 1:
				subparts = split2.split(input_stripped)
				subpartsall = ""
				if len(subparts) > 1:
					cnt = 1
					while cnt < len(subparts):
						subpartsall += subparts[cnt] + colon_arg
						cnt += 1
					subsubparts = split3.split(subpartsall)
					thisinstruction = subsubparts[0].strip()
			return thispointer, thisinstruction
	else:
		return thispointer, thisinstruction

def getNrOfDictElements(thisdict):
	"""
	Will get the total number of entries in a given dictionary
	Argument: the source dictionary
	Output : an integer
	"""
	total = 0
	for dicttype in thisdict:
		for dictval in thisdict[dicttype]:
			total += 1
	return total


class WalkLevel:
	"""
	Combinable bitmask flags controlling which heap/PEB structures are populated.

	Heap structure flags (0x001-0x100) can be OR-ed freely — each selects an
	independent structure to populate on an MnHeap instance.
	PEB entity flags (0x10000+) select which top-level entities MnPEB.__init__
	populates eagerly.
	"""
	NONE       = 0x00000
	# Heap structure flags (independent, combinable)
	HEAP       = 0x00001
	SEGMENT    = 0x00002
	VADBLOCK   = 0x00004
	FREELIST   = 0x00008
	LISTHINT   = 0x00010
	LFH        = 0x00020
	SUBSEGMENT = 0x00040
	BUCKET     = 0x00080
	CHUNK      = 0x00100
	# PEB entity flags (combinable)
	MODULES  = 0x00010000
	HEAPS    = 0x00020000
	# MnProc process-level population flags
	PEB      = 0x00040000
	TEBS     = 0x00080000
	STACKS   = 0x00200000
	# Composite convenience flags
	CORE     = PEB | TEBS
	STANDARD = CORE | STACKS | MODULES
	ALL      = STANDARD | HEAPS

	@classmethod
	def to_dict(cls):
		return {k: v for k, v in cls.__dict__.items()
				if not k.startswith('_') and not callable(v)}


class MnPEB:
	"""
	Class representing the Process Environment Block (PEB).
	Reads fields directly from memory using the cached PEB address.
	"""
 
	_nt_global_flag_definitions = {
		0x0: 			["","No GFlags enabled"],
		0x00000001:		["soe", "Stop On Execute"],
		0x00000002:		["sls", "Show Loader Snaps"],
		0x00000004:		["dic", "Debug Initial Command"],
		0x00000008:		["shg", "Stop On Hung GUI"],
		0x00000010:		["htc", "Enable Heap Tail Checking"],
		0x00000020:		["hfc", "Enable Heap Free Checking"],
		0x00000080:		["hvc", "Enable Heap Validation On Call"],
  		0x00000100:		["vrf", "Enable Application Verifier"],
		0x00000200:		["   ", "Enable Silent Process Exit Monitoring"],
  		0x00000400:     ["ptg", "Enable Pool Tagging"],
		0x00000800:		["htg", "Enable Heap Tagging"],
		0x00001000:		["ust", "Create User Mode Stack Trace"],
		0x00002000:		["kst", "Create Kernel Mode Stack Trace"],
		0x00004000:		["otl", "Maintain A List Of Objects For Each Type"],
		0x00008000:		["htd", "Enable Heap Tagging By DLL"],
		0x00010000:		["dse", "Disable Stack Extension"],
		0x00020000:		["d32", "Enable Debugging Of Win32 Subsystem"],
		0x00040000:		["ksl", "Enable Loading Of Kernel Debugger Symbols"],
		0x00080000:		["dps", "Disable Paging Of Kernel Stacks"],
		0x00100000:		["scb", "Enable System Critical Breaks"],
		0x00200000:		["dhc", "Disable Heap Coalesce On Free"],
		0x00400000:		["ece", "Enable Close Exception"],
		0x00800000:		["eel", "Enable Exception Logging"],
		0x01000000:		["eot", "Early Object Handle Type Tagging"],
		0x02000000:		["hpa", "Enable Page Heap"],
		0x04000000:		["dwl", "Debug WinLogon"],
		0x08000000:		["ddp", "Buffer DbgPrint Output"],
		0x10000000:		["cse", "Early Critical Section Event Creation"],
		0x40000000:		["bhd", "Disable Bad Handles Detection"],
		0x80000000:		["dpd", "Disable Protected DLL Verification"],
	}

	# PEB field offsets: (offset_x86, offset_x64)
	_offsets = {
		"ImageBaseAddress":     (0x08, 0x10),
		"Ldr":                  (0x0C, 0x18),
		"ProcessParameters":    (0x10, 0x20),
		"ProcessHeap":          (0x18, 0x30),
		"NumberOfHeaps":        (0x88, 0xE8),
		"MaximumNumberOfHeaps": (0x8C, 0xEC),
		"ProcessHeaps":         (0x90, 0xF0),
		"NtGlobalFlag":         (0x68, 0xBC),
		"OSMajorVersion":       (0xA4, 0x118),
		"OSMinorVersion":       (0xA8, 0x11C),
		"OSBuildNumber":        (0xAC, 0x120),
	}

	# PEB_LDR_DATA list head offsets: (x86, x64)
	_ldr_list_info = {
		"InLoadOrderModuleList": {
			"head_offset": (0x0C, 0x10),
			"link_offset": (0x00, 0x00),
		},
		"InMemoryOrderModuleList": {
			"head_offset": (0x14, 0x20),
			"link_offset": (0x08, 0x10),
		},
		"InInitializationOrderModuleList": {
			"head_offset": (0x1C, 0x30),
			"link_offset": (0x10, 0x20),
		},
	}

	# LDR_DATA_TABLE_ENTRY field offsets: (x86, x64)
	_dll_base_off   = (0x18, 0x30)
	_full_name_off  = (0x24, 0x48)
	_base_name_off  = (0x2C, 0x58)
 
	@staticmethod
	def getArch():
		return 1 if arch == 64 else 0

	# TODO: move part of procHideDebug here, we want patching to be done via MnPEB
	def __init__(self, walk_level=WalkLevel.NONE):
		try:
			addr = dbg.get_peb_addr()
		except Exception:
			addr = None
		if addr is None:
			try:
				teb = dbg.get_teb_addr()
			except Exception:
				try:
					tid = dbg.getThreadId()
					teb = dbg.getAllThreads()[tid].getTEB() or 0
				except Exception:
					teb = 0
			if teb:
				if arch == 32:
					addr = struct.unpack('<L', dbg.readMemory(teb + 0x30, 4))[0]
				else:
					addr = struct.unpack('<Q', dbg.readMemory(teb + 0x60, 8))[0]
		self.address = int(addr) if addr is not None else 0
		if self.address == 0:
			raise Exception("Unable to determine PEB address")

		def _read_ptr(addr):
			return struct.unpack(PTR_FMT, dbg.readMemory(addr, PTR_SIZE))[0]

		def _read_dword(addr):
			return struct.unpack('<L', dbg.readMemory(addr, 4))[0]

		self.ImageBaseAddress     = _read_ptr(self.address + self._offsets["ImageBaseAddress"][MnPEB.getArch()])
		self.Ldr                  = _read_ptr(self.address + self._offsets["Ldr"][MnPEB.getArch()])
		self.ProcessParameters    = _read_ptr(self.address + self._offsets["ProcessParameters"][MnPEB.getArch()])
		self.ProcessHeap          = _read_ptr(self.address + self._offsets["ProcessHeap"][MnPEB.getArch()])
		self.NumberOfHeaps        = _read_dword(self.address + self._offsets["NumberOfHeaps"][MnPEB.getArch()])
		self.MaximumNumberOfHeaps = _read_dword(self.address + self._offsets["MaximumNumberOfHeaps"][MnPEB.getArch()])
		self.ProcessHeaps         = _read_ptr(self.address + self._offsets["ProcessHeaps"][MnPEB.getArch()])
		self.OSMajorVersion       = _read_dword(self.address + self._offsets["OSMajorVersion"][MnPEB.getArch()])
		self.OSMinorVersion       = _read_dword(self.address + self._offsets["OSMinorVersion"][MnPEB.getArch()])
		self.OSBuildNumber        = struct.unpack('<H', dbg.readMemory(self.address + self._offsets["OSBuildNumber"][MnPEB.getArch()], 2))[0]

		self._ldr_list        = None
		self._modules_by_name = {}
		self._modules_by_base = {}
		self._raw_by_name     = {}
		self._populating_ldr  = False
		self._walk_params     = None   # (from_memory, peb_order) of last successful walk
		self._nt_global_flag  = None
		self._heaps           = None  # {heapbase: MnHeap} once populated

		if walk_level & WalkLevel.MODULES:
			self._walk_modules()
		if walk_level & WalkLevel.HEAPS:
			self._walk_heaps(walk_level)

	def get_address(self):
		"""Return the PEB address stored on this instance."""
		return self.address

	def getNtGlobalFlag(self):
		"""Return the cached NtGlobalFlag value read from the PEB."""
		if self._nt_global_flag is None:
			offset = self._offsets["NtGlobalFlag"][MnPEB.getArch()]
			try:
				self._nt_global_flag = struct.unpack('<L', dbg.readMemory(self.address + offset, 4))[0]
			except:
				self._nt_global_flag = 0
		return self._nt_global_flag

	def getNtGlobalFlagValues(self, flag):
		"""
		Decomposes a bitmask flag into its individual component flags.
		"""
		available_flags = sorted(
			[k for k in self._nt_global_flag_definitions.keys() if k > 0], 
			reverse=True
		)

		return [flag_value for flag_value in available_flags if flag & flag_value]
    
	def getNtGlobalFlagNames(self, flag):
		"""
		Converts a bitmask flag into a list of short names (abbreviations).
		"""
		active_bits = self.getNtGlobalFlagValues(flag)
		names = [
			self._nt_global_flag_definitions[bit][0] 
			for bit in active_bits 
			if bit in self._nt_global_flag_definitions
		]
		return names
    
	def getNtGlobalFlagValueData(self, flag_value):
		"""
		Returns the [short_name, description] list for a specific flag value.
		Returns ["", ""] if the flag value is not defined.
		"""
		return self._nt_global_flag_definitions.get(flag_value, ["", ""])
    
	def getActiveFlagNames(self, flag_value):
		"""
		Returns a comma-separated string of short names for the active flags.
		If no flags are set, returns the description for 0x0.
		"""
		names = self.getNtGlobalFlagNames(flag_value)

		if not names:
			names = [self._nt_global_flag_definitions.get(0, ["", ""])[0]]
            
		return ",".join(names)
    
	def getNtGlobalFlagValueName(self, flag_value):
		"""
		Returns a formatted string: '+[shortname] - [description]'
		Example: '+hpc - Enable Heap Parameter Checking'
		"""
		short_name, description = self.getNtGlobalFlagValueData(flag_value)
		prefix = "+%s" % short_name if short_name.strip() else "    "
		return "%s - %s" % (prefix, description)

	def _iter_ldr(self, list_name="InLoadOrderModuleList"):
		"""Yield (dll_base, base_name, full_path) for every entry in *list_name*."""
		def _read_ptr(addr):
			data = dbg.readMemory(addr, PTR_SIZE)
			if len(data) < PTR_SIZE:
				return None
			return struct.unpack(PTR_FMT, data)[0]

		def _wstr(entry, off):
			data = dbg.readMemory(entry + off, 2)
			if len(data) < 2:
				return ""
			length  = struct.unpack('<H', data)[0]
			buf_ptr = _read_ptr(entry + off + PTR_SIZE)
			if not buf_ptr or length == 0:
				return ""
			raw = dbg.readMemory(buf_ptr, length)
			return raw.decode('utf-16-le', errors='replace')

		if not self.address:
			return
		ldr = _read_ptr(self.address + MnPEB._offsets["Ldr"][MnPEB.getArch()])
		if not ldr:
			return
		info          = MnPEB._ldr_list_info[list_name]
		list_head     = ldr + info["head_offset"][MnPEB.getArch()]
		link_off      = info["link_offset"][MnPEB.getArch()]
		dll_base_off  = MnPEB._dll_base_off[MnPEB.getArch()]
		full_name_off = MnPEB._full_name_off[MnPEB.getArch()]
		base_name_off = MnPEB._base_name_off[MnPEB.getArch()]
		flink = _read_ptr(list_head)
		while flink and flink != list_head:
			entry_base = flink - link_off
			dll_base   = _read_ptr(entry_base + dll_base_off)
			if dll_base is None:
				break
			yield dll_base, _wstr(entry_base, base_name_off), _wstr(entry_base, full_name_off)
			flink = _read_ptr(flink)
			if flink is None:
				break

	_PEB_ORDER_LIST = {
		"load":   "InLoadOrderModuleList",
		"memory": "InMemoryOrderModuleList",
		"init":   "InInitializationOrderModuleList",
	}

	def _collect_ldr_raw(self, from_memory=False, peb_order="load"):
		"""Phase 1: walk LDR lists and collect raw entries.

		*peb_order* selects which list is iterated first (determines module
		ordering in the cache).  *from_memory* (WinDBG only) uses the
		debugger's own module enumeration for the primary list instead of
		the PEB LDR walk.

		Populates self._raw_by_name so re-entrant _resolve_base_and_path
		calls during Phase 2 can resolve addresses without a second walk.

		Returns list_raw: {list_name: [(dll_base, base_name, full_path)]}
		"""
		primary    = self._PEB_ORDER_LIST.get(peb_order, "InLoadOrderModuleList")
		list_names = [primary] + [n for n in self._ldr_list_info if n != primary]

		list_raw  = {}
		raw_dedup = {}  # dll_base -> (base_name, full_path); first-seen wins
		for list_name in list_names:
			if from_memory and __DEBUGGERAPP__ == "WinDBG" and list_name == primary:
				entries = dbglib.getModulesFromDebugger()
			else:
				entries = list(self._iter_ldr(list_name))
				if not entries and __DEBUGGERAPP__ == "WinDBG":
					entries = dbglib.getModulesFromDebugger()
			list_raw[list_name] = entries
			for dll_base, base_name, full_path in entries:
				if dll_base not in raw_dedup:
					raw_dedup[dll_base] = (base_name, full_path)
		self._raw_by_name = {
			os.path.splitext(bn.lower())[0]: (db, fp)
			for db, (bn, fp) in raw_dedup.items()
		}
		return list_raw

	def _build_module_objects(self, list_raw):
		"""Phase 2: construct MnModule objects from collected raw entries.

		Populates self._ldr_list, self._modules_by_base, self._modules_by_name.
		"""
		mod_cache = {}
		result    = {}
		for list_name, entries in list_raw.items():
			modules = []
			for dll_base, base_name, full_path in entries:
				if dll_base in mod_cache:
					modules.append(mod_cache[dll_base])
				else:
					try:
						mod = MnModule(os.path.splitext(base_name)[0], mzbase=dll_base, path=full_path)
						mod_cache[dll_base] = mod
						modules.append(mod)
					except Exception:
						pass
			result[list_name] = modules
		self._ldr_list        = result
		self._modules_by_base = mod_cache
		self._modules_by_name = {m.moduleKey.lower(): m for m in mod_cache.values()}

	def _walk_modules(self, from_memory=False, peb_order="load"):
		"""Build and cache the full module list. Returns self._ldr_list.

		If called with params that differ from the previous walk, the cache
		is cleared and rebuilt.
		"""
		params = (from_memory, peb_order)
		if self._ldr_list is not None and self._walk_params == params:
			return self._ldr_list
		if self._populating_ldr:
			return {}
		# Reset caches when params differ from the last walk
		if self._ldr_list is not None:
			self._ldr_list        = None
			self._modules_by_base = {}
			self._modules_by_name = {}
			self._raw_by_name     = {}
		self._populating_ldr = True
		self._walk_params    = params
		try:
			self._build_module_objects(self._collect_ldr_raw(from_memory=from_memory, peb_order=peb_order))
		finally:
			self._populating_ldr = False
		return self._ldr_list

	def _locate_module(self, modulename):
		"""
		Return (dll_base, full_path) for *modulename*.
		Returns (0, '') if not found.

		When the cache is cold, triggers _walk_modules() to build it.
		During _walk_modules Phase 2 (re-entrant), uses _raw_by_name which
		was populated in Phase 1 before any MnModule construction began.

		Handles deduplicated keys of the form "<stem>_<hexaddr>" that are
		generated by getAllModules() when two modules share the same stem
		(e.g. msedge.exe and msedge.dll both strip to "msedge", so the second
		becomes "msedge_7ff9af680000").  The hex suffix IS the load address, so
		we parse it directly instead of doing a failed name-match walk.
		"""
		try:
			name_lower = os.path.splitext(modulename.lower())[0]
			if not self._populating_ldr:
				self._walk_modules()
			if self._ldr_list is not None:
				mod = self._modules_by_name.get(name_lower)
				if mod:
					return mod.moduleBase, mod.modulePath
			raw = self._raw_by_name.get(name_lower)
			if raw:
				return raw
			m = re.match(r'^(.+)_([0-9a-f]+)$', name_lower)
			if m:
				try:
					candidate = int(m.group(2), 16)
					if candidate >= 0x10000:
						return candidate, ""
				except ValueError:
					pass
			return 0, ""
		except Exception:
			return 0, ""

	def getModuleByName(self, module_name):
		"""Return the MnModule for *module_name* from the cache, or None."""
		if self._ldr_list is None:
			self._walk_modules()
		return self._modules_by_name.get(module_name.lower())

	def getModuleByAddress(self, addr):
		"""Return the MnModule whose range contains *addr* from the cache, or None."""
		if self._ldr_list is None:
			self._walk_modules()
		mod = self._modules_by_base.get(addr)
		if mod:
			return mod
		return next((m for m in self._modules_by_base.values()
					 if m.moduleBase <= addr <= m.moduleTop), None)

	def getModulesSortedByBase(self, reverse=False):
		"""Return all modules as [(name, MnModule)] sorted by load address."""
		return sorted(self.getModules().items(), key=lambda x: x[1].moduleBase, reverse=reverse)

	def getModulesSortedBySize(self, reverse=False):
		"""Return all modules as [(name, MnModule)] sorted by image size."""
		return sorted(self.getModules().items(), key=lambda x: x[1].moduleSize, reverse=reverse)

	def getModulesSortedByName(self, reverse=False):
		"""Return all modules as [(name, MnModule)] sorted alphabetically by key."""
		return sorted(self.getModules().items(), key=lambda x: x[0], reverse=reverse)

	def getModules(self, from_memory=False, peb_order="load"):
		"""Return all cached MnModule objects keyed by lowercase module stem.

		*from_memory* and *peb_order* are forwarded to the PEB walk so callers
		can request a specific enumeration mode without calling _walk_modules
		directly.  Subsequent calls with the same params are free (cache hit).
		"""
		self._walk_modules(from_memory=from_memory, peb_order=peb_order)
		return self._modules_by_name

	def _walk_heaps(self, walk_level=WalkLevel.HEAP):
		"""Walk all PEB heaps and populate _heaps cache.

		Each MnHeap is constructed with *walk_level* so _apply_walk_level()
		eagerly populates the structures selected by the bitmask.
		"""
		if self._heaps is None:
			self._heaps = {}
		ptrsize = archValue(4, 8)
		mndbg.dbgp("MnPEB._walk_heaps: NumberOfHeaps=%d ProcessHeaps=%s ptrsize=%d walk_level=%s" % (
			self.NumberOfHeaps,
			PTR_PRINT % self.ProcessHeaps if self.ProcessHeaps else "<none>",
			ptrsize,
			str(walk_level)
		))
		for idx in range(self.NumberOfHeaps):
			heaplist_entry = self.ProcessHeaps + idx * ptrsize
			try:
				heapaddr = readPtrSizeBytes(heaplist_entry)
				mndbg.dbgp("MnPEB._walk_heaps: heap[%d] listentry=%s -> %s" % (
					idx,
					PTR_PRINT % heaplist_entry,
					PTR_PRINT % heapaddr if heapaddr else "<none>"
				))
			except Exception as e:
				mndbg.dbgp("MnPEB._walk_heaps: failed to read heap[%d] at %s: %s" % (
					idx,
					PTR_PRINT % heaplist_entry,
					str(e)
				), errormode=False)
				continue
			if not heapaddr:
				mndbg.dbgp("MnPEB._walk_heaps: skipping heap[%d] because heap address is null" % idx, errormode=False)
				continue
			if heapaddr in self._heaps:
				mndbg.dbgp("MnPEB._walk_heaps: skipping heap[%d] duplicate %s" % (
					idx,
					PTR_PRINT % heapaddr
				), errormode=False)
				continue
			try:
				heap = MnHeap._instantiate_for_cache(heapaddr, walk_level)
				heap._apply_walk_level()
				self._heaps[heapaddr] = heap
				mndbg.dbgp("MnPEB._walk_heaps: added heap[%d] %s type=%s" % (
					idx,
					PTR_PRINT % heapaddr,
					str(heap.getHeapType())
				))
			except Exception as e:
				mndbg.dbgp("MnPEB._walk_heaps: failed to instantiate heap[%d] %s: %s" % (
					idx,
					PTR_PRINT % heapaddr,
					str(e)
				), errormode=False)

	def getHeapObject(self, heapbase, walk_level=WalkLevel.HEAP):
		"""Return the cached MnHeap for *heapbase*.

		Ensures all PEB heaps are populated first via _walk_heaps().
		Creates on-demand for heaps not in the PEB list (e.g. private heaps).
		"""
		if self._heaps is None:
			self._walk_heaps(walk_level)
		if heapbase not in self._heaps:
			heap = MnHeap._instantiate_for_cache(heapbase, walk_level)
			heap._apply_walk_level()
			self._heaps[heapbase] = heap
		return self._heaps[heapbase]

	def getHeaps(self):
		"""Return a list of MnHeap objects for all process heaps, in PEB order."""
		expected_heaps = int(getattr(self, "NumberOfHeaps", 0) or 0)
		cached_heaps = 0 if self._heaps is None else len(self._heaps)
		if self._heaps is None or (expected_heaps > 0 and cached_heaps < expected_heaps):
			mndbg.dbgp("MnPEB.getHeaps: refreshing heap cache (cached=%d expected=%d)" % (
				cached_heaps,
				expected_heaps
			))
			self._walk_heaps()
		return list(self._heaps.values())

	def getSegmentHeaps(self):
		"""Return MnHeap objects whose type is Segment."""
		return [h for h in self.getHeaps() if h.getHeapType() == HeapType.SEGMENT]

	def getNTHeaps(self):
		"""Return MnHeap objects whose type is NT."""
		return [h for h in self.getHeaps() if h.getHeapType() == HeapType.NT]

	def getProcessHeap(self):
		"""Return the MnHeap for the default process heap."""
		return self.getHeapObject(self.ProcessHeap)

	def getHeapByAddress(self, addr):
		"""Return the MnHeap whose base address is *addr*, or None."""
		if self._heaps is None:
			self._walk_heaps()
		return self._heaps.get(addr)
 
	def getSegmentByAddress(self, addr):
		"""Return (heap, segaddr, seginfo) for the segment containing *addr*, or None.

		Searches all NT heaps. seginfo keys: "base", "end", "firstentry", "lastentry".
		"""
		for heap in self.getNTHeaps():
			result = heap.getSegmentByAddress(addr)
			if result is not None:
				segaddr, info = result
				return heap, segaddr, info
		return None

class MnTEB:
	"""
	Class representing a Thread Environment Block (TEB).
	Reads fields directly from memory given a TEB address.
	"""

	# TEB / NT_TIB field offsets: (x86, x64)
	_offsets = {
		"ExceptionList": (0x00, 0x00),
		"StackBase":     (0x04, 0x08),
		"StackLimit":    (0x08, 0x10),
		"ProcessId":     (0x20, 0x40),  # ClientId.UniqueProcess
		"ThreadId":      (0x24, 0x48),  # ClientId.UniqueThread
	}

	def __init__(self, teb_addr, peb=None):
		self.addr = teb_addr

		# Reference to the shared MnPEB (from MnProc), not a new instance
		self.PEB = peb

		def _read_ptr(addr):
			return struct.unpack(PTR_FMT, dbg.readMemory(addr, PTR_SIZE))[0]

		def _read_dword(addr):
			return struct.unpack('<L', dbg.readMemory(addr, 4))[0]

		self.StackBase  = _read_ptr(teb_addr + self._offsets["StackBase"][MnPEB.getArch()])
		self.StackLimit = _read_ptr(teb_addr + self._offsets["StackLimit"][MnPEB.getArch()])
		self.ProcessId  = _read_dword(teb_addr + self._offsets["ProcessId"][MnPEB.getArch()])
		self.Id         = _read_dword(teb_addr + self._offsets["ThreadId"][MnPEB.getArch()])

		# SEH chain: list of [record_addr, handler_addr]; x64 has no chain
		if arch == 32:
			self.SEHChain = []
			nextrecord = _read_ptr(teb_addr + self._offsets["ExceptionList"][MnPEB.getArch()])
			while nextrecord != 0xFFFFFFFF and nextrecord != 0:
				try:
					nseh = _read_ptr(nextrecord)
					seh  = _read_ptr(nextrecord + 4)
					self.SEHChain.append([nextrecord, seh])
					nextrecord = nseh
				except Exception:
					break
			self.SEHCount = len(self.SEHChain)

	@staticmethod
	def getByAddress(teb_addr):
		"""Return the MnTEB with the given TEB address from the MnProc cache, or None."""
		MnProc.ensure()
		mnproc.getThreads()
		for tid, mteb in mnproc.getThreads().items():
			if mteb.addr == teb_addr:
				return mteb
		return None

# TODO: move into MnModule
def getModuleObj(modname):
	"""
	Will return a module object if the provided module name exists
	Will perform a case sensitive search first,
	and then a case insensitive search in case nothing was found
	"""
	# Method 1
	mod = dbgGetModuleSafe(modname)
	if mod is not None:
		return MnModule(modname)
	# Method 2

	suffixes = ["",".exe",".dll"]
	allmod = dbg.getAllModules()
	for suf in suffixes:
		modname_search = modname + suf	
		
		#WinDBG optimized
		if mndbg.isWinDBG():	
			for tmod_s in allmod:
				tmod = dbgGetModuleSafe(tmod_s)
				if not tmod == None:
					if tmod.getName() == modname_search:
						return MnModule(tmod_s)
					imname = dbg.getImageNameForModule(tmod.getName())
					if not imname == None:
						if imname == modname_search:
							return MnModule(tmod)
			for tmod_s in allmod:
				tmod = dbgGetModuleSafe(tmod_s)
				if not tmod == None:
					if tmod.getName().lower() == modname_search.lower():
						return MnModule(tmod_s)
					imname = dbg.getImageNameForModule(tmod.getName().lower())
					if not imname == None:
						if imname.lower() == modname_search.lower():
							return MnModule(tmod)
			for tmod_s in allmod:
				tmod = dbgGetModuleSafe(tmod_s)
				if not tmod == None:
					if tmod_s.lower() == modname_search.lower():
						return MnModule(tmod_s)
		else:
			# Immunity
			for tmod_s in allmod:
				if not tmod_s == None:
					mname = tmod_s.getName()
					if mname == modname_search:
						return MnModule(mname)
			for tmod_s in allmod:
				if not tmod_s == None:
					mname = tmod_s.getName()
					if mname.lower() == modname_search.lower():
						return MnModule(mname)
		
	return None
	
		
		
def getPatternLength(startptr, pattern_type="normal", args=None):
	"""
	Gets length of a cyclic pattern, starting from a given pointer
	
	Arguments:
	startptr - the start pointer (integer value)
	pattern_type - optional string, indicating type of pattern :
		"normal" : normal pattern
		"unicode" : unicode pattern
		"upper" : uppercase pattern
		"lower" : lowercase pattern
	"""
	patternsize = 0
	endofpattern = False
	global g_silent

	if args is None:
		args = {}

	oldsilent = g_silent
	g_silent = True
	fullpattern = ensure_bytes(createPattern(200000, args))
	g_silent = oldsilent

	if pattern_type == "upper":
		fullpattern = fullpattern.upper()
	if pattern_type == "lower":
		fullpattern = fullpattern.lower()
	#if pattern_type == "unicode":
	#	fullpattern = toUnicode(fullpattern)

	if pattern_type in ["normal", "upper", "lower", "unicode"]:
		previousloc = -1
		while not endofpattern and patternsize <= len(fullpattern):
			if pattern_type == "unicode":
				sizemeter = dbg.readMemory(startptr + patternsize, 8)
				sizemeter = sizemeter.replace(b"\x00", b"")
			else:
				sizemeter = dbg.readMemory(startptr + patternsize, 4)

			if len(sizemeter) == 4:
				thisloc = fullpattern.find(sizemeter)
				if thisloc < 0 or thisloc <= previousloc:
					endofpattern = True
				else:
					patternsize += 4
					previousloc = thisloc
			else:
				return patternsize

		# maybe this is not the end yet
		patternsize -= 8
		endofpattern = False

		while not endofpattern and patternsize <= len(fullpattern):
			if pattern_type == "unicode":
				sizemeter = dbg.readMemory(startptr + patternsize, 8)
				sizemeter = sizemeter.replace(b"\x00", b"")
			else:
				sizemeter = dbg.readMemory(startptr + patternsize, 4)

			if fullpattern.find(sizemeter) < 0:
				patternsize += 3
				endofpattern = True
			else:
				patternsize += 1

	if pattern_type == "unicode":
		patternsize = (patternsize // 2) + 1

	return patternsize
	
def getAPointer(modules,criteria,accesslevel):
	"""
	Gets the first pointer from one of the supplied module that meets a set of criteria
	
	Arguments:
	modules - array with module names
	criteria - dictionary describing the criteria the pointer needs to comply with
	accesslevel - the required access level
	
	Return:
	a pointer (integer value) or 0 if nothing was found
	"""
	pointer = 0
	dbg.getMemoryPages()
	for a in dbg.MemoryPages.keys():
			page_start = a
			page_size  = dbg.MemoryPages[a].getSize()
			page_end   = a + page_size
			#page in one of the modules ?
			if meetsAccessLevel(dbg.MemoryPages[a],accesslevel):
				pageptr = MnPointer(a)
				thismodulename = pageptr.belongsTo()
				if thismodulename != "" and thismodulename in modules:
					thismod = MnModule(thismodulename)
					start = thismod.moduleBase
					end = thismod.moduleTop
					random.seed()
					for cnt in xrange(page_size+1):
						#randomize the value
						theoffset = random.randint(0,page_size)
						thispointer = MnPointer(page_start + theoffset)
						if meetsCriteria(thispointer,criteria):
							return page_start + theoffset
	return pointer
	
	
def haveRepetition(string, pos):
	first =  string[pos]
	MIN_REPETITION = 3		
	if len(string) - pos > MIN_REPETITION:
		count = 1
		while ( count < MIN_REPETITION and string[pos+count] ==  first):
			count += 1
		if count >= MIN_REPETITION:
			return True
	return False


def findAllPaths(graph,start_vertex,end_vertex,path=[]):
	path = path + [start_vertex]
	if start_vertex == end_vertex:
		return [path]
	if start_vertex not in graph:
		return []
	paths = []
	for vertex in graph[start_vertex]:
		if vertex not in path:
			extended_paths = findAllPaths(graph,vertex,end_vertex,path)
			for p in extended_paths:
				paths.append(p)
	return paths



def isAsciiString(data):
	"""
	Check if a given string only contains ascii characters
	"""
	return all((_ord(c) >= 32 and _ord(c) <= 127) for c in data)
	
def isAscii(b):
	"""
	Check if a given hex byte is ascii or not
	
	Argument : the byte
	Returns : Boolean
	"""
	return b == 0x0a or b == 0x0d or (b >= 0x20 and b <= 0x7e)
	
def isAscii2(b):
	"""
	Check if a given hex byte is ascii or not, will not flag newline or carriage return as ascii
	
	Argument : the byte
	Returns : Boolean
	"""
	return b >= 0x20 and b <= 0x7e	
	
def isHexString(input):
	"""
	Checks if all characters in a string are hex (0->9, a->f, A->F)
	Alias for isAddress()
	"""
	return isAddress(input)

def extract_chunks(iterable, size):
	""" Retrieves chunks of the given :size from the :iterable """
	fill = object()
	gen = izip_longest(fillvalue=fill, *([iter(iterable)] * size))
	return (tuple(x for x in chunk if x != fill) for chunk in gen)

def rrange(x, y = 0):
	""" Creates a reversed range (from x - 1 down to y).
	
	Example:
	>>> rrange(10, 0) # => [9, 8, 7, 6, 5, 4, 3, 2, 1, 0]
	"""
	return range(x - 1, y - 1, -1)

