def shortJump(sizeofinst, offset):
	"""
	Calculate the parameter for a short relative jump from the size of instruction (which can be JMP, JNZ etc...) and the desired offset
	Arguments:
	sizeofinst - the size of the instruction used to achieve the jump
	offset - the desired offset from the address of the instruction
	Return:
	A binary value which can be used along with the jump instruction
	"""
	if (offset - sizeofinst) < -128 or (offset - sizeofinst) > 127:
		dbg.log(" ** short jump too long",highlight=1)
	return struct.pack("b", offset - sizeofinst)

def archValue(x86, x64):
	if arch == 32:
		return x86
	elif arch == 64:
		return x64

def readPtrSizeBytes(ptr):
	data = dbg.readMemory(ptr, PTR_SIZE)
	expected = PTR_SIZE
	fmt = PTR_FMT
	if not data or len(data) < expected:
		mndbg.dbgp("readPtrSizeBytes(0x%x): readMemory returned %s bytes" % (ptr, len(data) if data else 0))
		return 0
	return struct.unpack(fmt, data)[0]


def _extractFunctionMetadataFromUfOutput(uf_output):
	mndbg.dbgp(get_current_function_name())
	result = OrderedDict([
		("function_start", 0),
		("symbol", ""),
	])
	if not uf_output:
		return result
	for raw_line in ensure_text(uf_output).splitlines():
		line = raw_line.strip()
		if line == "":
			continue
		if line.endswith(":") and "!" in line:
			result["symbol"] = line[:-1].strip()
			continue
		parts = line.split()
		if len(parts) < 2:
			continue
		addr = _tryParseAddressToken(parts[0])
		if addr > 0:
			result["function_start"] = addr
			break
	return result
	return struct.unpack(fmt, data)[0]

def _parseOsVersion():
	global g_os_version
	if g_os_version is None:
		mndbg.dbgp("No OS Version known, crawling it")
		osrelease = dbg.getOsRelease()
		mndbg.dbgp("_parseOsVersion(): osrelease='%s' (type: %s)" % (str(osrelease), type(osrelease).__name__))

		g_os_version = {
			"major": 0,
			"minor": 0,
			"build": 0,
			"category": "xp"
		}

		if isinstance(osrelease, tuple):
			# Immunity format: (Major, Minor, Build, Platform, CSD)
			try:
				g_os_version["major"] = int(osrelease[0])
				g_os_version["minor"] = int(osrelease[1])
				g_os_version["build"] = int(osrelease[2])
			except:
				pass
		else:
			# WinDBG format: "major.minor.build"
			osreleaseparts = str(osrelease).split(".")
			if len(osreleaseparts) >= 3:
				try:
					g_os_version["major"] = int(osreleaseparts[0])
					g_os_version["minor"] = int(osreleaseparts[1])
					g_os_version["build"] = int(osreleaseparts[2])
				except:
					pass

		major = g_os_version["major"]
		minor = g_os_version["minor"]
		build = g_os_version["build"]
  
		if major == 10:
			if build >= 22000:
				offset_category = "win11"
			else:
				offset_category = "win10"
		elif major == 6:
			if minor == 0: offset_category = "vista"
			elif minor == 1: offset_category = "win7"
			elif minor in [2,3]: offset_category = "win8"
			else: offset_category = "vista"
		else:
			offset_category = "xp"

		g_os_version["category"] = offset_category


