# 1st level functions that get called when running a mona command
#-----------------------------------------------------------------------#	

# ----- Config file management ----- #


def procCleanLog(args):
	minage = 30
	argerror = False
	statmode = False
	if "d" in args:
		if type(args["d"]).__name__.lower() == "bool":
			argerror = True
		else:
			try:
				minage = int(args["d"])
				if minage < 0:
					argerror = True
			except:
				argerror = True
	if "stat" in args and type(args["stat"]).__name__.lower() == "bool":
		statmode = True
	
	if argerror:
		dbg.log("** Please specific a valid number of days with -d", highlight = True)
		dbg.log("   or omit the parameter to use the default of 30", highlight = True)
		return

	monaConfig = MnConfig()
	configworkingfolder = monaConfig.get("workingfolder")

	if configworkingfolder != "":
		fixedworkingfolder = configworkingfolder
		placeholderpos = len(fixedworkingfolder)
		for placeholder in ["%p", "%i"]:
			thispos = fixedworkingfolder.find(placeholder)
			if thispos > -1 and thispos < placeholderpos:
				placeholderpos = thispos
		fixedworkingfolder = fixedworkingfolder[:placeholderpos].rstrip("\\/")
		if fixedworkingfolder != "":
			dbg.log("[+] Working folder base path: %s" % fixedworkingfolder)
			if os.path.exists(fixedworkingfolder):
				deletedFiles = {}
				logFiles = {}
				statFiles = {}
				deleteindex = 1
				logindex = 1
				totaldeletedsizekb = 0
				totaldeletedsizemb = "0.00 MB"
				now = time.time()
				for root, dirs, files in os.walk(fixedworkingfolder):
					for thisfile in files:
						thisfile_lc = thisfile.lower()
						matches = False
						if thisfile_lc.endswith("mona-windbg-debug.log"):
							matches = True
						if thisfile_lc.endswith(".old"):
							matches = True
						if thisfile_lc.endswith(".old2"):
							matches = True
						if "tellme" in thisfile_lc and thisfile_lc.endswith(".json"):
							matches = True	
						if "rop" in thisfile_lc and "progress" in thisfile_lc and thisfile_lc.endswith(".log"):
							matches = True
						if "bridge" in thisfile_lc and thisfile_lc.endswith(".log"):
							matches = True
						if matches:
							fullpath = os.path.join(root, thisfile)
							try:
								mtime = os.path.getmtime(fullpath)
								age = int((now - mtime) / 86400)
								filesizekb = int(round(float(os.path.getsize(fullpath)) / 1024))
								if statmode:
									logFiles[logindex] = [root, thisfile, age, "%dKB" % filesizekb]
									logindex += 1
									statkey = age
									if age > minage:
										statkey = ">%d" % minage
									if not statkey in statFiles:
										statFiles[statkey] = filesizekb
									else:
										statFiles[statkey] += filesizekb
								else:
									if age > minage or (minage == 0 and age >= 0):
										os.remove(fullpath)
										deletedFiles[deleteindex] = [root, thisfile, age, "%dKB" % filesizekb]
										totaldeletedsizekb += filesizekb
										deleteindex += 1
							except Exception as e:
								mndbg.dbgp("Unable to remove file %s: %s" % (fullpath, str(e)), errormode=False)
				totaldeletedsizemb = "%.2f MB" % (float(totaldeletedsizekb) / 1024)
				
				# show results
				if statmode:
					if len(logFiles) > 0:
						dbg.log("[+] Done. Found %d matching files:" % len(logFiles))
						headers = ["Index", "Folder","File","Age","Size in KB"]
						types   = ["int", "string", "string", "int", "string"]
						print_dict_table(logFiles, headers, types, padding = "    ")
						dbg.log("")
						dbg.log("[+] Size overview by age:")
						for statkey in sorted([k for k in statFiles if str(k).startswith(">") == False]):
							dbg.log("    %s day(s): %dKB" % (str(statkey), statFiles[statkey]))
						if (">%d" % minage) in statFiles:
							dbg.log("    >%d day(s): %dKB" % (minage, statFiles[">%d" % minage]))
						dbg.log("")
					else:
						dbg.log("[+] Done. No matching log files found")
				else:
					if len(deletedFiles) > 0:
						dbg.log("[+] Done. I have deleted %d files:" % len(deletedFiles))
						headers = ["Index", "Folder","File","Age","Size in KB"]
						types   = ["int", "string", "string", "int", "string"]

						print_dict_table(deletedFiles, headers, types, padding = "    ")	
						dbg.log("")
						dbg.log("[+] Total disk space saved: %s" % totaldeletedsizemb)
						dbg.log("")
					else:
						dbg.log("[+] Done. No files found that met the age criteria of %d days" % minage)
			else:
				dbg.log("[!] That folder does not seem to exist", highlight = True)
	else:
		dbg.log("[!] No 'workingfolder' parameter found in mona's config", highlight = True)
	
	dbg.log("")
	return


	

def procConfig(args):
	#did we specify -get, -set, -add, -list or -del?
	showerror = False
	showlist = False
	listarg = ""
	missing_del_value = False
	if not "set" in args and not "get" in args and not "add" in args and not "del" in args and not "list" in args:
		showlist = True

	if "list" in args:
		if type(args["list"]).__name__.lower() != "bool":
			listarg = args["list"]
			showlist = True

	if "set" in args:
		if type(args["set"]).__name__.lower() == "bool":
			showerror = True
		else:
			#count nr of words
			params = args["set"].split(" ")
			if len(params) < 2:
				showerror = True

	if "add" in args:
		if type(args["add"]).__name__.lower() == "bool":
			showerror = True
		else:
			#count nr of words
			params = args["add"].split(" ")
			if len(params) < 2:
				showerror = True

	if "get" in args:
		if type(args["get"]).__name__.lower() == "bool":
			showerror = True
		else:
			#count nr of words
			params = args["get"].split(" ")
			if len(params) < 1:
				showerror = True
	
	if "del" in args:
		if type(args["del"]).__name__.lower() == "bool":
			missing_del_value = True
		else:
			#count nr of words
			params = args["del"].split(" ")
			if len(params) < 2:
				missing_del_value = True
	
	if "clear" in args:
		if type(args["clear"]).__name__.lower() == "bool":
			showerror = True
		else:
			#count nr of words
			params = args["clear"].split(" ")
			if len(params) < 1:
				showerror = True	


	if missing_del_value:
		dbg.log("[!] Invalid arguments for -del", highlight=True)
		dbg.log("    Use -del <parameter> <value1,value2,...> to remove one or more values from a parameter", highlight=True)
		dbg.log("    If you want to remove the actual parameter instead, use -clear <parameter>", highlight=True)
		return

	if showerror:
		dbg.log("Invalid arguments - check the help for this command")
		#dbg.logLines(configUsage,highlight=1)
		return
	else:
		monaConfig = MnConfig()
		configfilename = monaConfig.getFileName()

		if "list" in args or showlist:
			dbg.log("[+] Listing all parameters and values stored in configuration file")
			if listarg:
				dbg.log("    Filter: %s" % listarg)
			dbg.log("    Config file: %s" % configfilename)
			dbg.log("")
			monaConfig.list(keyword=listarg)

		if "get" in args:
			dbg.log("[+] Reading value from configuration file")
			dbg.log("    Config file: %s" % configfilename)
			dbg.log("")
			paramname = args["get"].split(" ")[0]
			thevalue = monaConfig.get(paramname)
			configDict = {}
			headers = ["Parameter", "Value"]
			types   = ["string", "string"]
			configDict[paramname] = [thevalue]
			print_dict_table(configDict, headers, types, padding = "    ", itemsequence = [])
		
		if "set" in args:
			value = args["set"].split(" ")
			configparam = value[0].strip()
			dbg.log("[+] Saving new value for parameter '%s'" % configparam)
			dbg.log("    Config file: %s" % configfilename)
			dbg.log("    Old value of parameter %s = %s" % (configparam,monaConfig.get(configparam)))
			dbg.log("    New value:")
			dbg.log("")
			configvalue = args["set"][0+len(configparam):len(args["set"])]
			if configparam.lower() == "excluded_modules":
				configvalue = configvalue.replace(";", ",")
			if configparam.lower() == "alias":
				configvalue = configvalue.replace("#", "!")
			monaConfig.set(configparam,configvalue)
			configDict = {}
			headers = ["Parameter", "New value"]
			types   = ["string", "string"]
			configDict[configparam] = [configvalue]
			print_dict_table(configDict, headers, types, padding = "    ", itemsequence = [])
			
		if "clear" in args:
			value = args["clear"].split(" ")
			configparam = value[0].strip()
			dbg.log("[+] Attempting to clear config parameter '%s'" % configparam)
			dbg.log("    Config file: %s" % configfilename)
			dbg.log("    Current value of parameter %s = %s" % (configparam,monaConfig.get(configparam)))
			monaConfig.clear(configparam)
			dbg.log("    Parameter %s cleared / removed" % (configparam), highlight=True)
			dbg.log("")
			dbg.log("[+] Listing current values from configuration file:")
			dbg.log("")
			monaConfig.list()

		
		if "add" in args:
			value = args["add"].split(" ")
			configparam = value[0].strip()
			dbg.log("[+] Adding additional value(s) to parameter '%s'" % configparam)
			dbg.log("    Config file: %s" % configfilename)
			dbg.log("    Old value of parameter %s = %s" % (configparam,monaConfig.get(configparam)))
			oldvalue = monaConfig.get(configparam)
			if oldvalue is None:
				oldvalue = ""
			oldvalue = oldvalue.strip()
			newvalue_str = args["add"][0+len(configparam):len(args["add"])].strip()
			
			# Split old values and new values by comma
			old_values = [v.strip() for v in oldvalue.split(",") if v.strip()]
			new_values = [v.strip() for v in newvalue_str.split(",") if v.strip()]
			
			added_values = []
			skipped_values = []
			
			for new_val in new_values:
				if new_val in old_values:
					skipped_values.append(new_val)
					dbg.log("    Skipping '%s' - already present in parameter '%s'" % (new_val, configparam))
				else:
					added_values.append(new_val)
					old_values.append(new_val)
			
			if added_values:
				configvalue = ",".join(old_values)
				monaConfig.set(configparam, configvalue)
				dbg.log("    Added value(s): %s" % ", ".join(added_values))
			else:
				configvalue = oldvalue
				dbg.log("    No new values added")
			
			dbg.log("    New value:")
			dbg.log("")
			configDict = {}
			headers = ["Parameter", "New value"]
			types   = ["string", "string"]
			configDict[configparam] = [configvalue]
			print_dict_table(configDict, headers, types, padding = "    ", itemsequence = [])			



		if "del" in args:
			value = args["del"].split(" ")
			configparam = value[0].strip()
			delvalue_str = args["del"][0+len(configparam):len(args["del"])].strip()

			# get the current values
			currentvalues = monaConfig.get(configparam)
			if currentvalues is None:
				currentvalues = ""
			valueslist = [v.strip() for v in currentvalues.split(",") if v.strip()]
			
			# Split the values to delete by comma
			del_values = [v.strip() for v in delvalue_str.split(",") if v.strip()]
			
			newlist = valueslist[:]
			removed_values = []
			not_found_values = []
			
			for del_val in del_values:
				if del_val in newlist:
					newlist.remove(del_val)
					removed_values.append(del_val)
				else:
					not_found_values.append(del_val)
			
			configvalue = ",".join(newlist)

			dbg.log("[+] Attempting to remove value(s) '%s' from parameter '%s'" % (delvalue_str, configparam))
			dbg.log("    Config file: %s" % configfilename)

			dbg.log("    Current value of parameter %s = %s" % (configparam, monaConfig.get(configparam)))
			monaConfig.set(configparam, configvalue)
			
			if removed_values:
				dbg.log("    Removed value(s): %s" % ", ".join(removed_values), highlight = True)
			if not_found_values:
				dbg.log("    Value(s) not found: %s" % ", ".join(not_found_values), highlight = True)
			
			dbg.log("")
			configDict = {}
			headers = ["Parameter", "New value"]
			types   = ["string", "string"]
			configDict[configparam] = [configvalue]
			print_dict_table(configDict, headers, types, padding = "    ", itemsequence = [])



		
